def prove_nfbidv(sys: System) -> Proof:
    """An equality theorem for nonfreeness.  See ~ nfbidf for a version without
    disjoint variable condition but requiring more axioms.  (Contributed by
    Mario Carneiro, 4-Oct-2016.)  Remove dependency on ~ ax-6 , ~ ax-7 ,
    ~ ax-12 by adapting proof of ~ nfbidf .  (Revised by BJ,
    25-Sep-2022.)
    """
    lb = ProofBuilder(sys, "nfbidv")
    h1 = lb.hyp("albidv.1", "( φ → ( ψ ↔ χ ) )")
    s1 = lb.ref("s1", "( φ → ( ∃ x ψ ↔ ∃ x χ ) )", h1, ref="exbidv", note="exbidv")
    s2 = lb.ref("s2", "( φ → ( ∀ x ψ ↔ ∀ x χ ) )", h1, ref="albidv", note="albidv")
    s3 = lb.ref("s3", "( φ → ( ( ∃ x ψ → ∀ x ψ ) ↔ ( ∃ x χ → ∀ x χ ) ) )", s1, s2, ref="imbi12d", note="imbi12d")
    s4 = lb.ref("s4", "( F/ x ψ ↔ ( ∃ x ψ → ∀ x ψ ) )", ref="df-nf", note="df-nf")
    s5 = lb.ref("s5", "( F/ x χ ↔ ( ∃ x χ → ∀ x χ ) )", ref="df-nf", note="df-nf")
    res = lb.ref("res", "( φ → ( F/ x ψ ↔ F/ x χ ) )", s3, s4, s5, ref="3bitr4g", note="3bitr4g")
    return lb.build(res)

