    s2 = lb.ref("s2", "( ∃ x ψ → ψ )", ref="ax5e", note="ax5e")
    s3 = lb.ref("s3", "( ∀ x ( φ → ψ ) → ( ∃ x φ → ψ ) )", s1, s2, ref="syl6", note="syl6")
    s4 = lb.ref("s4", "( ψ → ∀ x ψ )", ref="ax-5", note="ax-5")
    s5 = lb.ref("s5", "( ( ∃ x φ → ψ ) → ( ∃ x φ → ∀ x ψ ) )", s4, ref="imim2i", note="imim2i")
