    s7 = lb.ref("s7", "( ( ∃ x φ → ψ ) → ∀ x ( φ → ψ ) )", s5, s6, ref="syl", note="syl")
    res = lb.ref("res", "( ∀ x ( φ → ψ ) ↔ ( ∃ x φ → ψ ) )", s3, s7, ref="impbii", note="impbii")
    return lb.build(res)

