def prove_3exdistr(sys: System) -> Proof:
    """Distribution of existential quantifiers in a triple conjunction.
    (Contributed by NM, 9-Mar-1995.)  (Proof shortened by Andrew Salmon,
    25-May-2011.)
    """
    lb = ProofBuilder(sys, "3exdistr")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ∧ χ ) ↔ ( φ ∧ ( ψ ∧ χ ) ) )", ref="3anass", note="3anass")
    s2 = lb.ref("s2", "( ∃ y ∃ z ( φ ∧ ψ ∧ χ ) ↔ ∃ y ∃ z ( φ ∧ ( ψ ∧ χ ) ) )", s1, ref="2exbii", note="2exbii")
    s3 = lb.ref("s3", "( ∃ y ∃ z ( φ ∧ ( ψ ∧ χ ) ) ↔ ( φ ∧ ∃ y ∃ z ( ψ ∧ χ ) ) )", ref="19.42vv", note="19.42vv")
    s4 = lb.ref("s4", "( ∃ y ∃ z ( ψ ∧ χ ) ↔ ∃ y ( ψ ∧ ∃ z χ ) )", ref="exdistr", note="exdistr")
    s5 = lb.ref("s5", "( ( φ ∧ ∃ y ∃ z ( ψ ∧ χ ) ) ↔ ( φ ∧ ∃ y ( ψ ∧ ∃ z χ ) ) )", s4, ref="anbi2i", note="anbi2i")
    s6 = lb.ref("s6", "( ∃ y ∃ z ( φ ∧ ψ ∧ χ ) ↔ ( φ ∧ ∃ y ( ψ ∧ ∃ z χ ) ) )", s2, s3, s5, ref="3bitri", note="3bitri")
    res = lb.ref("res", "( ∃ x ∃ y ∃ z ( φ ∧ ψ ∧ χ ) ↔ ∃ x ( φ ∧ ∃ y ( ψ ∧ ∃ z χ ) ) )", s6, ref="exbii", note="exbii")
