def prove_4exdistr(sys: System) -> Proof:
    """Distribution of existential quantifiers in a quadruple conjunction.
    (Contributed by NM, 9-Mar-1995.)  (Proof shortened by Wolf Lammen,
    20-Jan-2018.)
    """
    lb = ProofBuilder(sys, "4exdistr")
    s1 = lb.ref("s1", "( ∃ w ( χ ∧ θ ) ↔ ( χ ∧ ∃ w θ ) )", ref="19.42v", note="19.42v")
    s2 = lb.ref("s2", "( ( ( φ ∧ ψ ) ∧ ∃ w ( χ ∧ θ ) ) ↔ ( ( φ ∧ ψ ) ∧ ( χ ∧ ∃ w θ ) ) )", s1, ref="anbi2i", note="anbi2i")
    s3 = lb.ref("s3", "( ∃ w ( ( φ ∧ ψ ) ∧ ( χ ∧ θ ) ) ↔ ( ( φ ∧ ψ ) ∧ ∃ w ( χ ∧ θ ) ) )", ref="19.42v", note="19.42v")
    s4 = lb.ref("s4", "( ( φ ∧ ψ ∧ ( χ ∧ ∃ w θ ) ) ↔ ( ( φ ∧ ψ ) ∧ ( χ ∧ ∃ w θ ) ) )", ref="df-3an", note="df-3an")
    s5 = lb.ref("s5", "( ∃ w ( ( φ ∧ ψ ) ∧ ( χ ∧ θ ) ) ↔ ( φ ∧ ψ ∧ ( χ ∧ ∃ w θ ) ) )", s2, s3, s4, ref="3bitr4i", note="3bitr4i")
    s6 = lb.ref("s6", "( ∃ x ∃ y ∃ z ∃ w ( ( φ ∧ ψ ) ∧ ( χ ∧ θ ) ) ↔ ∃ x ∃ y ∃ z ( φ ∧ ψ ∧ ( χ ∧ ∃ w θ ) ) )", s5, ref="3exbii", note="3exbii")
    s7 = lb.ref("s7", "( ∃ x ∃ y ∃ z ( φ ∧ ψ ∧ ( χ ∧ ∃ w θ ) ) ↔ ∃ x ( φ ∧ ∃ y ( ψ ∧ ∃ z ( χ ∧ ∃ w θ ) ) ) )", ref="3exdistr", note="3exdistr")
    res = lb.ref("res", "( ∃ x ∃ y ∃ z ∃ w ( ( φ ∧ ψ ) ∧ ( χ ∧ θ ) ) ↔ ∃ x ( φ ∧ ∃ y ( ψ ∧ ∃ z ( χ ∧ ∃ w θ ) ) ) )", s6, s7, ref="bitri", note="bitri")
    return lb.build(res)

def prove_speimfw(sys: System) -> Proof:
    """Specialization, with additional weakening (compared to ~ 19.2 ) to allow
    bundling of ` x ` and ` y ` .  Uses only Tarski's FOL axiom schemes.
    (Contributed by NM, 23-Apr-2017.)  (Proof shortened by Wolf Lammen,
    5-Dec-2017.)
    """
    lb = ProofBuilder(sys, "speimfw")
    h1 = lb.hyp("speimfw.2", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "( ∃ x x = y ↔ ¬ ∀ x ¬ x = y )", ref="df-ex", note="df-ex")
    s2 = lb.ref("s2", "( ¬ ∀ x ¬ x = y → ∃ x x = y )", s1, ref="biimpri", note="biimpri")
    s3 = lb.ref("s3", "( φ → ( x = y → ψ ) )", h1, ref="com12", note="com12")
    s4 = lb.ref("s4", "( ∀ x φ → ( ∃ x x = y → ∃ x ψ ) )", s3, ref="aleximi", note="aleximi")
    res = lb.ref("res", "( ¬ ∀ x ¬ x = y → ( ∀ x φ → ∃ x ψ ) )", s2, s4, ref="syl5com", note="syl5com")
    return lb.build(res)

def prove_speimfwALT(sys: System) -> Proof:
    """Alternate proof of ~ speimfw (longer compressed proof, but fewer
    essential steps).  (Contributed by NM, 23-Apr-2017.)  (Proof shortened
    by Wolf Lammen, 5-Aug-2017.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "speimfwALT")
    h1 = lb.hyp("speimfw.2", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "( ∃ x x = y → ∃ x ( φ → ψ ) )", h1, ref="eximi", note="eximi")
    s2 = lb.ref("s2", "( ∃ x x = y ↔ ¬ ∀ x ¬ x = y )", ref="df-ex", note="df-ex")
    s3 = lb.ref("s3", "( ∃ x ( φ → ψ ) ↔ ( ∀ x φ → ∃ x ψ ) )", ref="19.35", note="19.35")
    res = lb.ref("res", "( ¬ ∀ x ¬ x = y → ( ∀ x φ → ∃ x ψ ) )", s1, s2, s3, ref="3imtr3i", note="3imtr3i")
    return lb.build(res)

def prove_spimfw(sys: System) -> Proof:
    """Specialization, with additional weakening (compared to ~ sp ) to allow
    bundling of ` x ` and ` y ` .  Uses only Tarski's FOL axiom schemes.
    (Contributed by NM, 23-Apr-2017.)  (Proof shortened by Wolf Lammen,
    7-Aug-2017.)
    """
    lb = ProofBuilder(sys, "spimfw")
    h1 = lb.hyp("spimfw.1", "( ¬ ψ → ∀ x ¬ ψ )")
    h2 = lb.hyp("spimfw.2", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "( ¬ ∀ x ¬ x = y → ( ∀ x φ → ∃ x ψ ) )", h2, ref="speimfw", note="speimfw")
    s2 = lb.ref("s2", "( ∃ x ψ ↔ ¬ ∀ x ¬ ψ )", ref="df-ex", note="df-ex")
    s3 = lb.ref("s3", "( ¬ ∀ x ¬ ψ → ψ )", h1, ref="con1i", note="con1i")
    s4 = lb.ref("s4", "( ∃ x ψ → ψ )", s2, s3, ref="sylbi", note="sylbi")
    res = lb.ref("res", "( ¬ ∀ x ¬ x = y → ( ∀ x φ → ψ ) )", s1, s4, ref="syl6", note="syl6")
    return lb.build(res)

def prove_ax12i(sys: System) -> Proof:
    """Inference that has ~ ax-12 (without ` A. y ` ) as its conclusion.  Uses
    only Tarski's FOL axiom schemes.  The hypotheses may be eliminable
    without using ~ ax-12 in special cases.  Proof similar to Lemma 16 of
    [Tarski] p. 70.  (Contributed by NM, 20-May-2008.)
    """
    lb = ProofBuilder(sys, "ax12i")
    h1 = lb.hyp("ax12i.1", "( x = y → ( φ ↔ ψ ) )")
    h2 = lb.hyp("ax12i.2", "( ψ → ∀ x ψ )")
    s1 = lb.ref("s1", "( ψ → ( x = y → φ ) )", h1, ref="biimprcd", note="biimprcd")
    s2 = lb.ref("s2", "( ψ → ∀ x ( x = y → φ ) )", h2, s1, ref="alrimih", note="alrimih")
    res = lb.ref("res", "( x = y → ( φ → ∀ x ( x = y → φ ) ) )", h1, s2, ref="biimtrdi", note="biimtrdi")
    return lb.build(res)

def prove_ax6v(sys: System) -> Proof:
    """Axiom B7 of [Tarski] p. 75, which requires that ` x ` and ` y ` be
    distinct.  This trivial proof is intended merely to weaken Axiom ~ ax-6
    by adding a distinct variable restriction ($d).  From here on, ~ ax-6
    should not be referenced directly by any other proof, so that Theorem
    ~ ax6 will show that we can recover ~ ax-6 from this weaker version if
    it were an axiom (as it is in the case of Tarski).

    Note:  Introducing ` x , y ` as a distinct variable group "out of the
    blue" with no apparent justification has puzzled some people, but it is
    perfectly sound.  All we are doing is adding an additional prerequisite,
    similar to adding an unnecessary logical hypothesis, that results in a
    weakening of the theorem.  This means that any _future_ theorem that
    references ~ ax6v must have a $d specified for the two variables that
    get substituted for ` x ` and ` y ` .  The $d does not propagate
    "backwards", i.e., it does not impose a requirement on ~ ax-6 .

    When possible, use of this theorem rather than ~ ax6 is preferred since
    its derivation is much shorter and requires fewer axioms.  (Contributed
    by NM, 7-Aug-2015.)
    """
    lb = ProofBuilder(sys, "ax6v")
    res = lb.ref("res", "¬ ∀ x ¬ x = y", ref="ax-6", note="ax-6")
    return lb.build(res)

def prove_ax6ev(sys: System) -> Proof:
    """At least one individual exists.  Weaker version of ~ ax6e .  When
    possible, use of this theorem rather than ~ ax6e is preferred since its
    derivation is much shorter and requires fewer axioms.  (Contributed by
    NM, 3-Aug-2017.)
    """
    lb = ProofBuilder(sys, "ax6ev")
    s1 = lb.ref("s1", "¬ ∀ x ¬ x = y", ref="ax6v", note="ax6v")
    s2 = lb.ref("s2", "( ∃ x x = y ↔ ¬ ∀ x ¬ x = y )", ref="df-ex", note="df-ex")
    res = lb.ref("res", "∃ x x = y", s1, s2, ref="mpbir", note="mpbir")
    return lb.build(res)

def prove_spimw(sys: System) -> Proof:
    """Specialization.  Lemma 8 of [KalishMontague] p. 87.  Uses only Tarski's
    FOL axiom schemes.  (Contributed by NM, 19-Apr-2017.)  (Proof shortened
    by Wolf Lammen, 7-Aug-2017.)
    """
    lb = ProofBuilder(sys, "spimw")
    h1 = lb.hyp("spimw.1", "( ¬ ψ → ∀ x ¬ ψ )")
    h2 = lb.hyp("spimw.2", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "¬ ∀ x ¬ x = y", ref="ax6v", note="ax6v")
    s2 = lb.ref("s2", "( ¬ ∀ x ¬ x = y → ( ∀ x φ → ψ ) )", h1, h2, ref="spimfw", note="spimfw")
    res = lb.mp("res", s1, s2, "ax-mp")
    return lb.build(res)

def prove_spimew(sys: System) -> Proof:
    """Existential introduction, using implicit substitution.  Compare Lemma 14
    of [Tarski] p. 70.  (Contributed by NM, 7-Aug-1994.)  (Proof shortened
    by Wolf Lammen, 22-Oct-2023.)
    """
    lb = ProofBuilder(sys, "spimew")
    h1 = lb.hyp("spimew.1", "( φ → ∀ x φ )")
    h2 = lb.hyp("spimew.2", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "¬ ∀ x ¬ x = y", ref="ax6v", note="ax6v")
    s2 = lb.ref("s2", "( ¬ ∀ x ¬ x = y → ( ∀ x φ → ∃ x ψ ) )", h2, ref="speimfw", note="speimfw")
    res = lb.ref("res", "( φ → ∃ x ψ )", s1, h1, s2, ref="mpsyl", note="mpsyl")
    return lb.build(res)

def prove_speiv(sys: System) -> Proof:
    """Inference from existential specialization.  (Contributed by NM,
    19-Aug-1993.)  Use ~ spimew .  (Revised by Wolf Lammen, 22-Oct-2023.)
    """
    lb = ProofBuilder(sys, "speiv")
    h1 = lb.hyp("speiv.1", "( x = y → ( ψ → φ ) )")
    h2 = lb.hyp("speiv.2", "ψ")
    s1 = lb.ref("s1", "( ψ → ∀ x ψ )", h2, ref="hbth", note="hbth")
    s2 = lb.ref("s2", "( ψ → ∃ x φ )", s1, h1, ref="spimew", note="spimew")
    res = lb.mp("res", h2, s2, "ax-mp")
    return lb.build(res)

def prove_speivw(sys: System) -> Proof:
    """Version of ~ spei with a disjoint variable condition, which does not
    require ~ ax-13 (neither ~ ax-7 nor ~ ax-12 ).  (Contributed by BJ,
    31-May-2019.)
    """
    lb = ProofBuilder(sys, "speivw")
    h1 = lb.hyp("speivw.1", "( x = y → ( φ ↔ ψ ) )")
    h2 = lb.hyp("speivw.2", "ψ")
    s1 = lb.ref("s1", "( x = y → ( ψ → φ ) )", h1, ref="biimprd", note="biimprd")
    res = lb.ref("res", "∃ x φ", s1, h2, ref="speiv", note="speiv")
    return lb.build(res)

def prove_exgen(sys: System) -> Proof:
    """Rule of existential generalization, similar to universal generalization
    ~ ax-gen , but valid only if an individual exists.  Its proof requires
    ~ ax-6 in our axiomatization but the equality predicate does not occur
    in its statement.  Some fundamental theorems of predicate calculus can
    be proven from ~ ax-gen , ~ ax-4 and this theorem alone, not requiring
    ~ ax-7 or excessive distinct variable conditions.  (Contributed by Wolf
    Lammen, 12-Nov-2017.)  (Proof shortened by Wolf Lammen, 20-Oct-2023.)
    """
    lb = ProofBuilder(sys, "exgen")
    h1 = lb.hyp("exgen.1", "φ")
    s1 = lb.ref("s1", "( x = y → ( φ → φ ) )", ref="idd", note="idd")
    res = lb.ref("res", "∃ x φ", s1, h1, ref="speiv", note="speiv")
    return lb.build(res)

def prove_extru(sys: System) -> Proof:
    """There exists a variable such that ` T. ` holds; that is, there exists a
    variable.  This corresponds under the standard translation to one of the
    formulations of the modal axiom (D), the other being ~ 19.2 .
    (Contributed by Anthony Hart, 13-Sep-2011.)  (Proof shortened by BJ,
    12-May-2019.)
    """
    lb = ProofBuilder(sys, "extru")
    s1 = lb.ref("s1", "⊤", ref="tru", note="tru")
    res = lb.ref("res", "∃ x ⊤", s1, ref="exgen", note="exgen")
    return lb.build(res)

def prove_19_2(sys: System) -> Proof:
    """Theorem 19.2 of [Margaris] p. 89.  This corresponds to the axiom (D) of
    modal logic (the other standard formulation being ~ extru ).  Note:  This
    proof is very different from Margaris' because we only have Tarski's FOL
    axiom schemes available at this point.  See the later ~ 19.2g for a more
    conventional proof of a more general result, which uses additional axioms.
    The reverse implication is the defining property of effective nonfreeness
    (see ~ df-nf ).  (Contributed by NM, 2-Aug-2017.)  Remove dependency on
    ~ ax-7 .  (Revised by Wolf Lammen, 4-Dec-2017.)
    """
    lb = ProofBuilder(sys, "19.2")
    s1 = lb.ref("s1", "( φ → φ )", ref="id", note="id")
    s2 = lb.ref("s2", "∃ x ( φ → φ )", s1, ref="exgen", note="exgen")
    res = lb.ref("res", "( ∀ x φ → ∃ x φ )", s2, ref="19.35i", note="19.35i")
    return lb.build(res)

def prove_19_2d(sys: System) -> Proof:
    """Deduction associated with ~ 19.2 .  (Contributed by BJ, 12-May-2019.)"""
    lb = ProofBuilder(sys, "19.2d")
    h1 = lb.hyp("19.2d.1", "( φ → ∀ x ψ )")
    s1 = lb.ref("s1", "( ∀ x ψ → ∃ x ψ )", ref="19.2", note="19.2")
    res = lb.ref("res", "( φ → ∃ x ψ )", h1, s1, ref="syl", note="syl")
    return lb.build(res)

def prove_19_8w(sys: System) -> Proof:
    """Weak version of ~ 19.8a and instance of ~ 19.2d .  (Contributed by NM,
    1-Aug-2017.)  (Proof shortened by Wolf Lammen, 4-Dec-2017.)
    """
    lb = ProofBuilder(sys, "19.8w")
    h1 = lb.hyp("19.8w.1", "( φ → ∀ x φ )")
    res = lb.ref("res", "( φ → ∃ x φ )", h1, ref="19.2d", note="19.2d")
    return lb.build(res)

def prove_spnfw(sys: System) -> Proof:
    """Weak version of ~ sp .  Uses only Tarski's FOL axiom schemes.
    (Contributed by NM, 1-Aug-2017.)  (Proof shortened by Wolf Lammen,
    13-Aug-2017.)
    """
    lb = ProofBuilder(sys, "spnfw")
    h1 = lb.hyp("spnfw.1", "( ¬ φ → ∀ x ¬ φ )")
    s1 = lb.ref("s1", "( x = y → ( φ → φ ) )", ref="idd", note="idd")
    res = lb.ref("res", "( ∀ x φ → φ )", h1, s1, ref="spimw", note="spimw")
    return lb.build(res)

def prove_spfalw(sys: System) -> Proof:
    """Version of ~ sp when ` ph ` is false.  Uses only Tarski's FOL axiom
    schemes.  (Contributed by NM, 23-Apr-2017.)  (Proof shortened by Wolf
    Lammen, 25-Dec-2017.)
    """
    lb = ProofBuilder(sys, "spfalw")
    h1 = lb.hyp("spfalw.1", "¬ φ")
    s1 = lb.ref("s1", "( ¬ φ → ∀ x ¬ φ )", h1, ref="hbth", note="hbth")
    res = lb.ref("res", "( ∀ x φ → φ )", s1, ref="spnfw", note="spnfw")
    return lb.build(res)

def prove_spvw(sys: System) -> Proof:
    """Version of ~ sp when ` x ` does not occur in ` ph ` .  Converse of
    ~ ax-5 .  Uses only Tarski's FOL axiom schemes.  (Contributed by NM,
    10-Apr-2017.)  (Proof shortened by Wolf Lammen, 4-Dec-2017.)  Shorten
    ~ 19.3v .  (Revised by Wolf Lammen, 20-Oct-2023.)
    """
    lb = ProofBuilder(sys, "spvw")
    s1 = lb.ref("s1", "( ¬ φ → ∀ x ¬ φ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ∀ x φ → φ )", s1, ref="spnfw", note="spnfw")
    return lb.build(res)

def prove_19_3v(sys: System) -> Proof:
    """Version of ~ 19.3 with a disjoint variable condition, requiring fewer
    axioms.  Any formula can be universally quantified using a variable
    which it does not contain.  See also ~ 19.9v .  (Contributed by Anthony
    Hart, 13-Sep-2011.)  Remove dependency on ~ ax-7 .  (Revised by Wolf
    Lammen, 4-Dec-2017.)  (Proof shortened by Wolf Lammen, 20-Oct-2023.)
    """
    lb = ProofBuilder(sys, "19.3v")
    s1 = lb.ref("s1", "( ∀ x φ → φ )", ref="spvw", note="spvw")
    s2 = lb.ref("s2", "( φ → ∀ x φ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ∀ x φ ↔ φ )", s1, s2, ref="impbii", note="impbii")
    return lb.build(res)

def prove_19_8v(sys: System) -> Proof:
    """Version of ~ 19.8a with a disjoint variable condition, requiring fewer
    axioms.  Converse of ~ ax5e .  (Contributed by BJ, 12-Mar-2020.)
    """
    lb = ProofBuilder(sys, "19.8v")
    s1 = lb.ref("s1", "( φ → ∀ x φ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( φ → ∃ x φ )", s1, ref="19.8w", note="19.8w")
    return lb.build(res)

def prove_19_9v(sys: System) -> Proof:
    """Version of ~ 19.9 with a disjoint variable condition, requiring fewer
    axioms.  Any formula can be existentially quantified using a variable
    which it does not contain.  See also ~ 19.3v .  (Contributed by NM,
    28-May-1995.)  Remove dependency on ~ ax-7 .  (Revised by Wolf Lammen,
    4-Dec-2017.)
    """
    lb = ProofBuilder(sys, "19.9v")
    s1 = lb.ref("s1", "( ∃ x φ → φ )", ref="ax5e", note="ax5e")
    s2 = lb.ref("s2", "( φ → ∃ x φ )", ref="19.8v", note="19.8v")
    res = lb.ref("res", "( ∃ x φ ↔ φ )", s1, s2, ref="impbii", note="impbii")
    return lb.build(res)

def prove_spimevw(sys: System) -> Proof:
    """Existential introduction, using implicit substitution.  This is to
    ~ spimew what ~ spimvw is to ~ spimw .  Version of ~ spimev and
    ~ spimefv with an additional disjoint variable condition, using only
    Tarski's FOL axiom schemes.  (Contributed by NM, 10-Jan-1993.)  (Revised
    by BJ, 17-Mar-2020.)
    """
    lb = ProofBuilder(sys, "spimevw")
    h1 = lb.hyp("spimevw.1", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "( φ → ∀ x φ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( φ → ∃ x ψ )", s1, h1, ref="spimew", note="spimew")
    return lb.build(res)

def prove_spimvw(sys: System) -> Proof:
    """A weak form of specialization.  Lemma 8 of [KalishMontague] p. 87.  Uses
    only Tarski's FOL axiom schemes.  For stronger forms using more axioms,
    see ~ spimv and ~ spimfv .  (Contributed by NM, 9-Apr-2017.)
    """
    lb = ProofBuilder(sys, "spimvw")
    h1 = lb.hyp("spimvw.1", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "( ¬ ψ → ∀ x ¬ ψ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ∀ x φ → ψ )", s1, h1, ref="spimw", note="spimw")
    return lb.build(res)

def prove_spsv(sys: System) -> Proof:
    """Generalization of antecedent.  A trivial weak version of ~ sps avoiding
    ~ ax-12 .  (Contributed by SN, 13-Nov-2025.)  (Proof shortened by WL,
    19-Nov-2025.)
    """
    lb = ProofBuilder(sys, "spsv")
    h1 = lb.hyp("spsv.1", "( φ → ψ )")
    s1 = lb.ref("s1", "( x = y → ( φ → ψ ) )", h1, ref="a1i", note="a1i")
    res = lb.ref("res", "( ∀ x φ → ψ )", s1, ref="spimvw", note="spimvw")
    return lb.build(res)

def prove_spvv(sys: System) -> Proof:
    """Specialization, using implicit substitution.  Version of ~ spv with a
    disjoint variable condition, which does not require ~ ax-7 , ~ ax-12 ,
    ~ ax-13 .  (Contributed by NM, 30-Aug-1993.)  (Revised by BJ,
    31-May-2019.)
    """
    lb = ProofBuilder(sys, "spvv")
    h1 = lb.hyp("spvv.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = y → ( φ → ψ ) )", h1, ref="biimpd", note="biimpd")
    res = lb.ref("res", "( ∀ x φ → ψ )", s1, ref="spimvw", note="spimvw")
    return lb.build(res)

def prove_chvarvv(sys: System) -> Proof:
    """Implicit substitution of ` y ` for ` x ` into a theorem.  Version of
    ~ chvarv with a disjoint variable condition, which does not require
    ~ ax-13 .  (Contributed by NM, 20-Apr-1994.)  (Revised by BJ,
    31-May-2019.)
    """
    lb = ProofBuilder(sys, "chvarvv")
    h1 = lb.hyp("chvarvv.1", "( x = y → ( φ ↔ ψ ) )")
    h2 = lb.hyp("chvarvv.2", "φ")
    s1 = lb.ref("s1", "( ∀ x φ → ψ )", h1, ref="spvv", note="spvv")
    res = lb.ref("res", "ψ", s1, h2, ref="mpg", note="mpg")
    return lb.build(res)

def prove_19_39(sys: System) -> Proof:
    """Theorem 19.39 of [Margaris] p. 90.  (Contributed by NM, 12-Mar-1993.)"""
    lb = ProofBuilder(sys, "19.39")
    s1 = lb.ref("s1", "( ∀ x φ → ∃ x φ )", ref="19.2", note="19.2")
    s2 = lb.ref("s2", "( ( ∃ x φ → ∃ x ψ ) → ( ∀ x φ → ∃ x ψ ) )", s1, ref="imim1i", note="imim1i")
    s3 = lb.ref("s3", "( ∃ x ( φ → ψ ) ↔ ( ∀ x φ → ∃ x ψ ) )", ref="19.35", note="19.35")
    res = lb.ref("res", "( ( ∃ x φ → ∃ x ψ ) → ∃ x ( φ → ψ ) )", s2, s3, ref="sylibr", note="sylibr")
    return lb.build(res)

def prove_19_24(sys: System) -> Proof:
    """Theorem 19.24 of [Margaris] p. 90.  (Contributed by NM, 12-Mar-1993.)"""
    lb = ProofBuilder(sys, "19.24")
    s1 = lb.ref("s1", "( ∀ x ψ → ∃ x ψ )", ref="19.2", note="19.2")
    s2 = lb.ref("s2", "( ( ∀ x φ → ∀ x ψ ) → ( ∀ x φ → ∃ x ψ ) )", s1, ref="imim2i", note="imim2i")
    s3 = lb.ref("s3", "( ∃ x ( φ → ψ ) ↔ ( ∀ x φ → ∃ x ψ ) )", ref="19.35", note="19.35")
    res = lb.ref("res", "( ( ∀ x φ → ∀ x ψ ) → ∃ x ( φ → ψ ) )", s2, s3, ref="sylibr", note="sylibr")
    return lb.build(res)

def prove_19_34(sys: System) -> Proof:
    """Theorem 19.34 of [Margaris] p. 90.  (Contributed by NM, 12-Mar-1993.)"""
    lb = ProofBuilder(sys, "19.34")
    s1 = lb.ref("s1", "( ∀ x φ → ∃ x φ )", ref="19.2", note="19.2")
    s2 = lb.ref("s2", "( ( ∀ x φ ∨ ∃ x ψ ) → ( ∃ x φ ∨ ∃ x ψ ) )", s1, ref="orim1i", note="orim1i")
    s3 = lb.ref("s3", "( ∃ x ( φ ∨ ψ ) ↔ ( ∃ x φ ∨ ∃ x ψ ) )", ref="19.43", note="19.43")
    res = lb.ref("res", "( ( ∀ x φ ∨ ∃ x ψ ) → ∃ x ( φ ∨ ψ ) )", s2, s3, ref="sylibr", note="sylibr")
    return lb.build(res)

def prove_19_36v(sys: System) -> Proof:
    """Version of ~ 19.36 with a disjoint variable condition instead of a
    nonfreeness hypothesis.  (Contributed by NM, 18-Aug-1993.)  Reduce
    dependencies on axioms.  (Revised by Wolf Lammen, 17-Jan-2020.)
    """
    lb = ProofBuilder(sys, "19.36v")
    s1 = lb.ref("s1", "( ∃ x ( φ → ψ ) ↔ ( ∀ x φ → ∃ x ψ ) )", ref="19.35", note="19.35")
    s2 = lb.ref("s2", "( ∃ x ψ ↔ ψ )", ref="19.9v", note="19.9v")
    s3 = lb.ref("s3", "( ( ∀ x φ → ∃ x ψ ) ↔ ( ∀ x φ → ψ ) )", s2, ref="imbi2i", note="imbi2i")
    res = lb.ref("res", "( ∃ x ( φ → ψ ) ↔ ( ∀ x φ → ψ ) )", s1, s3, ref="bitri", note="bitri")
    return lb.build(res)

def prove_19_12vvv(sys: System) -> Proof:
    """Version of ~ 19.12vv with a disjoint variable condition, requiring fewer
    axioms.  See also ~ 19.12 .  (Contributed by BJ, 18-Mar-2020.)
    """
    lb = ProofBuilder(sys, "19.12vvv")
    s1 = lb.ref("s1", "( ∀ y ( φ → ψ ) ↔ ( φ → ∀ y ψ ) )", ref="19.21v", note="19.21v")
    s2 = lb.ref("s2", "( ∃ x ∀ y ( φ → ψ ) ↔ ∃ x ( φ → ∀ y ψ ) )", s1, ref="exbii", note="exbii")
    s3 = lb.ref("s3", "( ∃ x ( φ → ∀ y ψ ) ↔ ( ∀ x φ → ∀ y ψ ) )", ref="19.36v", note="19.36v")
    s4 = lb.ref("s4", "( ∃ x ( φ → ψ ) ↔ ( ∀ x φ → ψ ) )", ref="19.36v", note="19.36v")
    s5 = lb.ref("s5", "( ∀ y ∃ x ( φ → ψ ) ↔ ∀ y ( ∀ x φ → ψ ) )", s4, ref="albii", note="albii")
    s6 = lb.ref("s6", "( ∀ y ( ∀ x φ → ψ ) ↔ ( ∀ x φ → ∀ y ψ ) )", ref="19.21v", note="19.21v")
    s7 = lb.ref("s7", "( ( ∀ x φ → ∀ y ψ ) ↔ ∀ y ∃ x ( φ → ψ ) )", s5, s6, ref="bitr2i", note="bitr2i")
    res = lb.ref("res", "( ∃ x ∀ y ( φ → ψ ) ↔ ∀ y ∃ x ( φ → ψ ) )", s2, s3, s7, ref="3bitri", note="3bitri")
    return lb.build(res)

