    lb = ProofBuilder(sys, "exsbim")
    s1 = lb.ref("s1", "( ∀ x ( x = y → φ ) → ∃ x φ )", ref="alequexv", note="alequexv")
    res = lb.ref("res", "( ∃ y ∀ x ( x = y → φ ) → ∃ x φ )", s1, ref="exlimiv", note="exlimiv")
