def prove_equsv(sys: System) -> Proof:
    """If a formula does not contain a variable ` x ` , then it is equivalent
    to the corresponding prototype of substitution with a fresh variable
    (see ~ sb6 ).  (Contributed by BJ, 23-Jul-2023.)
    """
    lb = ProofBuilder(sys, "equsv")
    s1 = lb.ref("s1", "( ∀ x ( x = y → φ ) ↔ ( ∃ x x = y → φ ) )", ref="19.23v", note="19.23v")
    s2 = lb.ref("s2", "∃ x x = y", ref="ax6ev", note="ax6ev")
    s3 = lb.ref("s3", "( φ ↔ ( ∃ x x = y → φ ) )", s2, ref="a1bi", note="a1bi")
    res = lb.ref("res", "( ∀ x ( x = y → φ ) ↔ φ )", s1, s3, ref="bitr4i", note="bitr4i")
    return lb.build(res)

def prove_equsalvw(sys: System) -> Proof:
    """Version of ~ equsalv with a disjoint variable condition, and of ~ equsal
    with two disjoint variable conditions, which requires fewer axioms.  See
    also the dual form ~ equsexvw .  (Contributed by BJ, 31-May-2019.)
    """
    lb = ProofBuilder(sys, "equsalvw")
    h1 = lb.hyp("equsalvw.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ( x = y → φ ) ↔ ( x = y → ψ ) )", h1, ref="pm5.74i", note="pm5.74i")
    s2 = lb.ref("s2", "( ∀ x ( x = y → φ ) ↔ ∀ x ( x = y → ψ ) )", s1, ref="albii", note="albii")
    s3 = lb.ref("s3", "( ∀ x ( x = y → ψ ) ↔ ψ )", ref="equsv", note="equsv")
    res = lb.ref("res", "( ∀ x ( x = y → φ ) ↔ ψ )", s2, s3, ref="bitri", note="bitri")
    return lb.build(res)

def prove_equsexvw(sys: System) -> Proof:
    """Version of ~ equsexv with a disjoint variable condition, and of ~ equsex
    with two disjoint variable conditions, which requires fewer axioms.  See
    also the dual form ~ equsalvw .  (Contributed by BJ, 31-May-2019.)
    (Proof shortened by Wolf Lammen, 23-Oct-2023.)
    """
    lb = ProofBuilder(sys, "equsexvw")
    h1 = lb.hyp("equsalvw.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ x ( x = y → ¬ φ ) ↔ ¬ ∃ x ( x = y ∧ φ ) )", ref="alinexa", note="alinexa")
    s2 = lb.ref("s2", "( x = y → ( ¬ φ ↔ ¬ ψ ) )", h1, ref="notbid", note="notbid")
    s3 = lb.ref("s3", "( ∀ x ( x = y → ¬ φ ) ↔ ¬ ψ )", s2, ref="equsalvw", note="equsalvw")
    s4 = lb.ref("s4", "( ¬ ∃ x ( x = y ∧ φ ) ↔ ¬ ψ )", s1, s3, ref="bitr3i", note="bitr3i")
    res = lb.ref("res", "( ∃ x ( x = y ∧ φ ) ↔ ψ )", s4, ref="con4bii", note="con4bii")
    return lb.build(res)

def prove_cbvaliw(sys: System) -> Proof:
    """Change bound variable.  Uses only Tarski's FOL axiom schemes.  Part of
    Lemma 7 of [KalishMontague] p. 86.  (Contributed by NM, 19-Apr-2017.)
    """
    lb = ProofBuilder(sys, "cbvaliw")
    h1 = lb.hyp("cbvaliw.1", "( ∀ x φ → ∀ y ∀ x φ )")
    h2 = lb.hyp("cbvaliw.2", "( ¬ ψ → ∀ x ¬ ψ )")
    h3 = lb.hyp("cbvaliw.3", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "( ∀ x φ → ψ )", h2, h3, ref="spimw", note="spimw")
    res = lb.ref("res", "( ∀ x φ → ∀ y ψ )", h1, s1, ref="alrimih", note="alrimih")
    return lb.build(res)

def prove_cbvalivw(sys: System) -> Proof:
    """Change bound variable.  Uses only Tarski's FOL axiom schemes.  Part of
    Lemma 7 of [KalishMontague] p. 86.  (Contributed by NM, 9-Apr-2017.)
    """
    lb = ProofBuilder(sys, "cbvalivw")
    h1 = lb.hyp("cbvalivw.1", "( x = y → ( φ → ψ ) )")
    s1 = lb.ref("s1", "( ∀ x φ → ψ )", h1, ref="spimvw", note="spimvw")
    res = lb.ref("res", "( ∀ x φ → ∀ y ψ )", s1, ref="alrimiv", note="alrimiv")
    return lb.build(res)

def prove_ax7v(sys: System) -> Proof:
    """Weakened version of ~ ax-7 , with a disjoint variable condition on
    ` x , y ` .  This should be the only proof referencing ~ ax-7 , and it
    should be referenced only by its two weakened versions ~ ax7v1 and
    ~ ax7v2 , from which ~ ax-7 is then rederived as ~ ax7 , which shows
    that either ~ ax7v or the conjunction of ~ ax7v1 and ~ ax7v2 is
    sufficient.

    In ~ ax7v , it is still allowed to substitute the same variable for
    ` x ` and ` z ` , or the same variable for ` y ` and ` z ` .  Therefore,
    ~ ax7v "bundles" (a term coined by Raph Levien) its "principal instance"
    ` ( x = y -> ( x = z -> y = z ) ) ` with ` x , y , z ` distinct, and its
    "degenerate instances" ` ( x = y -> ( x = x -> y = x ) ) ` and
    ` ( x = y -> ( x = y -> y = y ) ) ` with ` x , y ` distinct.  These
    degenerate instances are for instance used in the proofs of ~ equcomiv
    and ~ equid respectively.  (Contributed by BJ, 7-Dec-2020.)  Use ~ ax7
    instead.  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "ax7v")
    res = lb.ref("res", "( x = y → ( x = z → y = z ) )", ref="ax-7", note="ax-7")
    return lb.build(res)

def prove_ax7v1(sys: System) -> Proof:
    """First of two weakened versions of ~ ax7v , with an extra disjoint
    variable condition on ` x , z ` , see comments there.  (Contributed by
    BJ, 7-Dec-2020.)
    """
    lb = ProofBuilder(sys, "ax7v1")
    res = lb.ref("res", "( x = y → ( x = z → y = z ) )", ref="ax7v", note="ax7v")
    return lb.build(res)

def prove_ax7v2(sys: System) -> Proof:
    """Second of two weakened versions of ~ ax7v , with an extra disjoint
    variable condition on ` y , z ` , see comments there.  (Contributed by
    BJ, 7-Dec-2020.)
    """
    lb = ProofBuilder(sys, "ax7v2")
    res = lb.ref("res", "( x = y → ( x = z → y = z ) )", ref="ax7v", note="ax7v")
    return lb.build(res)

def prove_equid(sys: System) -> Proof:
    """Identity law for equality.  Lemma 2 of [KalishMontague] p. 85.  See also
    Lemma 6 of [Tarski] p. 68.  (Contributed by NM, 1-Apr-2005.)  (Revised
    by NM, 9-Apr-2017.)  (Proof shortened by Wolf Lammen, 22-Aug-2020.)
    """
    lb = ProofBuilder(sys, "equid")
    s1 = lb.ref("s1", "( y = x → ( y = x → x = x ) )", ref="ax7v1", note="ax7v1")
    s2 = lb.ref("s2", "( y = x → x = x )", s1, ref="pm2.43i", note="pm2.43i")
    s3 = lb.ref("s3", "∃ y y = x", ref="ax6ev", note="ax6ev")
    res = lb.ref("res", "x = x", s2, s3, ref="exlimiiv", note="exlimiiv")
    return lb.build(res)

def prove_nfequid(sys: System) -> Proof:
    """Bound-variable hypothesis builder for ` x = x ` .  This theorem tells us
    that any variable, including ` x ` , is effectively not free in
    ` x = x ` , even though ` x ` is technically free according to the
    traditional definition of free variable.  (Contributed by NM,
    13-Jan-2011.)  (Revised by NM, 21-Aug-2017.)
    """
    lb = ProofBuilder(sys, "nfequid")
    s1 = lb.ref("s1", "x = x", ref="equid", note="equid")
    res = lb.ref("res", "F/ y x = x", s1, ref="nfth", note="nfth")
    return lb.build(res)

def prove_equcomiv(sys: System) -> Proof:
    """Weaker form of ~ equcomi with a disjoint variable condition on
    ` x , y ` .  This is an intermediate step and ~ equcomi is fully
    recovered later.  (Contributed by BJ, 7-Dec-2020.)
    """
    lb = ProofBuilder(sys, "equcomiv")
    s1 = lb.ref("s1", "x = x", ref="equid", note="equid")
    s2 = lb.ref("s2", "( x = y → ( x = x → y = x ) )", ref="ax7v2", note="ax7v2")
    res = lb.ref("res", "( x = y → y = x )", s1, s2, ref="mpi", note="mpi")
    return lb.build(res)

def prove_ax6evr(sys: System) -> Proof:
    """A commuted form of ~ ax6ev .  (Contributed by BJ, 7-Dec-2020.)"""
    lb = ProofBuilder(sys, "ax6evr")
    s1 = lb.ref("s1", "∃ x x = y", ref="ax6ev", note="ax6ev")
    s2 = lb.ref("s2", "( x = y → y = x )", ref="equcomiv", note="equcomiv")
    res = lb.ref("res", "∃ x y = x", s1, s2, ref="eximii", note="eximii")
    return lb.build(res)

def prove_ax7(sys: System) -> Proof:
    """Proof of ~ ax-7 from ~ ax7v1 and ~ ax7v2 (and earlier axioms), proving
    sufficiency of the conjunction of the latter two weakened versions of
    ~ ax7v , which is itself a weakened version of ~ ax-7 .

    Note that the weakened version of ~ ax-7 obtained by adding a disjoint
    variable condition on ` x , z ` (resp. on ` y , z ` ) does not permit,
    together with the other axioms, to prove reflexivity (resp. symmetry).
    (Contributed by BJ, 7-Dec-2020.)
    """
    lb = ProofBuilder(sys, "ax7")
    s1 = lb.ref("s1", "( x = t → ( x = y → t = y ) )", ref="ax7v2", note="ax7v2")
    s2 = lb.ref("s2", "( x = t → ( x = z → t = z ) )", ref="ax7v2", note="ax7v2")
    s3 = lb.ref("s3", "( t = y → ( t = z → y = z ) )", ref="ax7v1", note="ax7v1")
    s4 = lb.ref("s4", "( ( t = y ∧ t = z ) → y = z )", s3, ref="imp", note="imp")
    s5 = lb.ref("s5", "( x = t → ( ( t = y ∧ t = z ) → y = z ) )", s4, ref="a1i", note="a1i")
    s6 = lb.ref("s6", "( x = t → ( ( x = y ∧ x = z ) → y = z ) )", s1, s2, s5, ref="syl2and", note="syl2and")
    s7 = lb.ref("s7", "∃ t x = t", ref="ax6evr", note="ax6evr")
    s8 = lb.ref("s8", "( ( x = y ∧ x = z ) → y = z )", s6, s7, ref="exlimiiv", note="exlimiiv")
    res = lb.ref("res", "( x = y → ( x = z → y = z ) )", s8, ref="ex", note="ex")
    return lb.build(res)

def prove_equcomi(sys: System) -> Proof:
    """Commutative law for equality.  Equality is a symmetric relation.  Lemma 3
    of [KalishMontague] p. 85.  See also Lemma 7 of [Tarski] p. 69.
    (Contributed by NM, 10-Jan-1993.)  (Revised by NM, 9-Apr-2017.)
    """
    lb = ProofBuilder(sys, "equcomi")
    s1 = lb.ref("s1", "x = x", ref="equid", note="equid")
    s2 = lb.ref("s2", "( x = y → ( x = x → y = x ) )", ref="ax7", note="ax7")
    res = lb.ref("res", "( x = y → y = x )", s1, s2, ref="mpi", note="mpi")
    return lb.build(res)

def prove_equcom(sys: System) -> Proof:
    """Commutative law for equality.  Equality is a symmetric relation.
    (Contributed by NM, 20-Aug-1993.)
    """
    lb = ProofBuilder(sys, "equcom")
    s1 = lb.ref("s1", "( x = y → y = x )", ref="equcomi", note="equcomi")
    s2 = lb.ref("s2", "( y = x → x = y )", ref="equcomi", note="equcomi")
    res = lb.ref("res", "( x = y ↔ y = x )", s1, s2, ref="impbii", note="impbii")
    return lb.build(res)

def prove_equcomd(sys: System) -> Proof:
    """Deduction form of ~ equcom , symmetry of equality.  For the versions for
    classes, see ~ eqcom and ~ eqcomd .  (Contributed by BJ, 6-Oct-2019.)
    """
    lb = ProofBuilder(sys, "equcomd")
    h1 = lb.hyp("equcomd.1", "( φ → x = y )")
    s1 = lb.ref("s1", "( x = y ↔ y = x )", ref="equcom", note="equcom")
    res = lb.ref("res", "( φ → y = x )", h1, s1, ref="sylib", note="sylib")
    return lb.build(res)

def prove_equcoms(sys: System) -> Proof:
    """An inference commuting equality in antecedent.  Used to eliminate the
    need for a syllogism.  (Contributed by NM, 10-Jan-1993.)
    """
    lb = ProofBuilder(sys, "equcoms")
    h1 = lb.hyp("equcoms.1", "( x = y → φ )")
    s1 = lb.ref("s1", "( y = x → x = y )", ref="equcomi", note="equcomi")
    res = lb.ref("res", "( y = x → φ )", s1, h1, ref="syl", note="syl")
    return lb.build(res)

def prove_equtr(sys: System) -> Proof:
    """A transitive law for equality.  (Contributed by NM, 23-Aug-1993.)"""
    lb = ProofBuilder(sys, "equtr")
    s1 = lb.ref("s1", "( y = x → ( y = z → x = z ) )", ref="ax7", note="ax7")
    res = lb.ref("res", "( x = y → ( y = z → x = z ) )", s1, ref="equcoms", note="equcoms")
    return lb.build(res)

def prove_equtrr(sys: System) -> Proof:
    """A transitive law for equality.  Lemma L17 in [Megill] p. 446 (p. 14 of the
    preprint).  (Contributed by NM, 23-Aug-1993.)
    """
    lb = ProofBuilder(sys, "equtrr")
    s1 = lb.ref("s1", "( z = x → ( x = y → z = y ) )", ref="equtr", note="equtr")
    res = lb.ref("res", "( x = y → ( z = x → z = y ) )", s1, ref="com12", note="com12")
    return lb.build(res)

def prove_equeuclr(sys: System) -> Proof:
    """Commuted version of ~ equeucl (equality is left-Euclidean).  (Contributed
    by BJ, 12-Apr-2021.)
    """
    lb = ProofBuilder(sys, "equeuclr")
    s1 = lb.ref("s1", "( z = x → ( y = z → y = x ) )", ref="equtrr", note="equtrr")
    res = lb.ref("res", "( x = z → ( y = z → y = x ) )", s1, ref="equcoms", note="equcoms")
    return lb.build(res)

def prove_equeucl(sys: System) -> Proof:
    """Equality is a left-Euclidean binary relation.  (Right-Euclideanness is
    stated in ~ ax-7 .)  Curried (exported) form of ~ equtr2 .  (Contributed
    by BJ, 11-Apr-2021.)
    """
    lb = ProofBuilder(sys, "equeucl")
    s1 = lb.ref("s1", "( y = z → ( x = z → x = y ) )", ref="equeuclr", note="equeuclr")
    res = lb.ref("res", "( x = z → ( y = z → x = y ) )", s1, ref="com12", note="com12")
    return lb.build(res)

def prove_equequ1(sys: System) -> Proof:
    """An equivalence law for equality.  (Contributed by NM, 1-Aug-1993.)  (Proof
    shortened by Wolf Lammen, 10-Dec-2017.)
    """
    lb = ProofBuilder(sys, "equequ1")
    s1 = lb.ref("s1", "( x = y → ( x = z → y = z ) )", ref="ax7", note="ax7")
    s2 = lb.ref("s2", "( x = y → ( y = z → x = z ) )", ref="equtr", note="equtr")
    res = lb.ref("res", "( x = y → ( x = z ↔ y = z ) )", s1, s2, ref="impbid", note="impbid")
    return lb.build(res)

def prove_equequ2(sys: System) -> Proof:
    """An equivalence law for equality.  (Contributed by NM, 21-Jun-1993.)
    (Proof shortened by Wolf Lammen, 4-Aug-2017.)  (Proof shortened by BJ,
    12-Apr-2021.)
    """
    lb = ProofBuilder(sys, "equequ2")
    s1 = lb.ref("s1", "( x = y → ( z = x → z = y ) )", ref="equtrr", note="equtrr")
    s2 = lb.ref("s2", "( x = y → ( z = y → z = x ) )", ref="equeuclr", note="equeuclr")
    res = lb.ref("res", "( x = y → ( z = x ↔ z = y ) )", s1, s2, ref="impbid", note="impbid")
    return lb.build(res)

def prove_equtr2(sys: System) -> Proof:
    """Equality is a left-Euclidean binary relation.  Uncurried (imported) form
    of ~ equeucl .  (Contributed by NM, 12-Aug-1993.)  (Proof shortened by
    Andrew Salmon, 25-May-2011.)  (Proof shortened by BJ, 11-Apr-2021.)
    """
    lb = ProofBuilder(sys, "equtr2")
    s1 = lb.ref("s1", "( x = z → ( y = z → x = y ) )", ref="equeucl", note="equeucl")
    res = lb.ref("res", "( ( x = z ∧ y = z ) → x = y )", s1, ref="imp", note="imp")
    return lb.build(res)

def prove_stdpc6(sys: System) -> Proof:
    """One of the two equality axioms of standard predicate calculus, called
    reflexivity of equality.  (The other one is ~ stdpc7 .)  Axiom 6 of
    [Mendelson] p. 95.  Mendelson doesn't say why he prepended the redundant
    quantifier, but it was probably to be compatible with free logic (which is
    valid in the empty domain).  (Contributed by NM, 16-Feb-2005.)
    """
    lb = ProofBuilder(sys, "stdpc6")
    s1 = lb.ref("s1", "x = x", ref="equid", note="equid")
    res = lb.ref("res", "∀ x x = x", s1, ref="ax-gen", note="ax-gen")
    return lb.build(res)

def prove_equvinv(sys: System) -> Proof:
    """A variable introduction law for equality.  Lemma 15 of [Monk2] p. 109.
    (Contributed by NM, 9-Jan-1993.)  Remove dependencies on ~ ax-10 ,
    ~ ax-13 .  (Revised by Wolf Lammen, 10-Jun-2019.)  Move the quantified
    variable ( ` z ` ) to the left of the equality signs.  (Revised by Wolf
    Lammen, 11-Apr-2021.)  (Proof shortened by Wolf Lammen, 12-Jul-2022.)
    """
    lb = ProofBuilder(sys, "equvinv")
    s1 = lb.ref("s1", "( z = x → ( z = y ↔ x = y ) )", ref="equequ1", note="equequ1")
    s2 = lb.ref("s2", "( ∃ z ( z = x ∧ z = y ) ↔ x = y )", s1, ref="equsexvw", note="equsexvw")
    res = lb.ref("res", "( x = y ↔ ∃ z ( z = x ∧ z = y ) )", s2, ref="bicomi", note="bicomi")
    return lb.build(res)

def prove_equvinva(sys: System) -> Proof:
    """A modified version of the forward implication of ~ equvinv adapted to
    common usage.  (Contributed by Wolf Lammen, 8-Sep-2018.)
    """
    lb = ProofBuilder(sys, "equvinva")
    s1 = lb.ref("s1", "∃ z y = z", ref="ax6evr", note="ax6evr")
    s2 = lb.ref("s2", "( x = y → ( y = z → x = z ) )", ref="equtr", note="equtr")
    s3 = lb.ref("s3", "( x = y → ( y = z → ( x = z ∧ y = z ) ) )", s2, ref="ancrd", note="ancrd")
    s4 = lb.ref("s4", "( x = y → ( ∃ z y = z → ∃ z ( x = z ∧ y = z ) ) )", s3, ref="eximdv", note="eximdv")
    res = lb.ref("res", "( x = y → ∃ z ( x = z ∧ y = z ) )", s1, s4, ref="mpi", note="mpi")
    return lb.build(res)

def prove_equvelv(sys: System) -> Proof:
    """A biconditional form of ~ equvel with disjoint variable conditions and
    proved from Tarski's FOL axiom schemes.  (Contributed by Andrew Salmon,
    2-Jun-2011.)  Reduce axiom usage.  (Revised by Wolf Lammen,
    10-Apr-2021.)  (Proof shortened by Wolf Lammen, 12-Jul-2022.)
    """
    lb = ProofBuilder(sys, "equvelv")
    s1 = lb.ref("s1", "( z = x → ( z = y ↔ x = y ) )", ref="equequ1", note="equequ1")
    res = lb.ref("res", "( ∀ z ( z = x → z = y ) ↔ x = y )", s1, ref="equsalvw", note="equsalvw")
    return lb.build(res)

def prove_ax13b(sys: System) -> Proof:
    """An equivalence between two ways of expressing ~ ax-13 .  See the comment
    for ~ ax-13 .  (Contributed by NM, 2-May-2017.)  (Proof shortened by Wolf
    Lammen, 26-Feb-2018.)  (Revised by BJ, 15-Sep-2020.)
    """
    lb = ProofBuilder(sys, "ax13b")
    s1 = lb.ref("s1", "( ( y = z → φ ) → ( ¬ x = z → ( y = z → φ ) ) )", ref="ax-1", note="ax-1")
    s2 = lb.ref("s2", "( y = z → ( x = z → x = y ) )", ref="equeuclr", note="equeuclr")
    s3 = lb.ref("s3", "( ¬ x = y → ( y = z → ¬ x = z ) )", s2, ref="con3rr3", note="con3rr3")
    s4 = lb.ref("s4", "( ¬ x = y → ( ( ¬ x = z → ( y = z → φ ) ) → ( y = z → ( y = z → φ ) ) ) )", s3, ref="imim1d", note="imim1d")
    s5 = lb.ref("s5", "( ( y = z → ( y = z → φ ) ) → ( y = z → φ ) )", ref="pm2.43", note="pm2.43")
    s6 = lb.ref("s6", "( ¬ x = y → ( ( ¬ x = z → ( y = z → φ ) ) → ( y = z → φ ) ) )", s4, s5, ref="syl6", note="syl6")
    s7 = lb.ref("s7", "( ¬ x = y → ( ( y = z → φ ) ↔ ( ¬ x = z → ( y = z → φ ) ) ) )", s1, s6, ref="impbid2", note="impbid2")
    res = lb.ref("res", "( ( ¬ x = y → ( y = z → φ ) ) ↔ ( ¬ x = y → ( ¬ x = z → ( y = z → φ ) ) ) )", s7, ref="pm5.74i", note="pm5.74i")
    return lb.build(res)

def prove_spfw(sys: System) -> Proof:
    """Weak version of ~ sp .  Uses only Tarski's FOL axiom schemes.  Lemma 9
    of [KalishMontague] p. 87.  This may be the best we can do with minimal
    distinct variable conditions.  (Contributed by NM, 19-Apr-2017.)  (Proof
    shortened by Wolf Lammen, 10-Oct-2021.)
    """
    lb = ProofBuilder(sys, "spfw")
    h1 = lb.hyp("spfw.1", "( ¬ ψ → ∀ x ¬ ψ )")
    h2 = lb.hyp("spfw.2", "( ∀ x φ → ∀ y ∀ x φ )")
    h3 = lb.hyp("spfw.3", "( ¬ φ → ∀ y ¬ φ )")
    h4 = lb.hyp("spfw.4", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = y → ( φ → ψ ) )", h4, ref="biimpd", note="biimpd")
    s2 = lb.ref("s2", "( ∀ x φ → ∀ y ψ )", h2, h1, s1, ref="cbvaliw", note="cbvaliw")
    s3 = lb.ref("s3", "( x = y → ( ψ → φ ) )", h4, ref="biimprd", note="biimprd")
    s4 = lb.ref("s4", "( y = x → ( ψ → φ ) )", s3, ref="equcoms", note="equcoms")
    s5 = lb.ref("s5", "( ∀ y ψ → φ )", h3, s4, ref="spimw", note="spimw")
    res = lb.ref("res", "( ∀ x φ → φ )", s2, s5, ref="syl", note="syl")
    return lb.build(res)

def prove_spw(sys: System) -> Proof:
    """Weak version of the specialization scheme ~ sp .  Lemma 9 of
    [KalishMontague] p. 87.  While it appears that ~ sp in its general form
    does not follow from Tarski's FOL axiom schemes, from this theorem we
    can prove any _instance_ of ~ sp having mutually distinct setvar
    variables and no wff metavariables (see ~ ax12wdemo for an example of
    the procedure to eliminate the hypothesis).  Other approximations of
    ~ sp are ~ spfw (minimal distinct variable requirements), ~ spnfw (when
    ` x ` is not free in ` -. ph ` ), ~ spvw (when ` x ` does not appear in
    ` ph ` ), ~ sptruw (when ` ph ` is true), ~ spfalw (when ` ph ` is
    false), and ~ spvv (where ` ph ` is changed into ` ps ` ).  (Contributed
    by NM, 9-Apr-2017.)  (Proof shortened by Wolf Lammen, 27-Feb-2018.)
    """
    lb = ProofBuilder(sys, "spw")
    h1 = lb.hyp("spw.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ¬ ψ → ∀ x ¬ ψ )", ref="ax-5", note="ax-5")
    s2 = lb.ref("s2", "( ∀ x φ → ∀ y ∀ x φ )", ref="ax-5", note="ax-5")
    s3 = lb.ref("s3", "( ¬ φ → ∀ y ¬ φ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ∀ x φ → φ )", s1, s2, s3, h1, ref="spfw", note="spfw")
    return lb.build(res)

def prove_cbvalw(sys: System) -> Proof:
    """Change bound variable.  Uses only Tarski's FOL axiom schemes.
    (Contributed by NM, 9-Apr-2017.)
    """
    lb = ProofBuilder(sys, "cbvalw")
    h1 = lb.hyp("cbvalw.1", "( ∀ x φ → ∀ y ∀ x φ )")
    h2 = lb.hyp("cbvalw.2", "( ¬ ψ → ∀ x ¬ ψ )")
    h3 = lb.hyp("cbvalw.3", "( ∀ y ψ → ∀ x ∀ y ψ )")
    h4 = lb.hyp("cbvalw.4", "( ¬ φ → ∀ y ¬ φ )")
    h5 = lb.hyp("cbvalw.5", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = y → ( φ → ψ ) )", h5, ref="biimpd", note="biimpd")
    s2 = lb.ref("s2", "( ∀ x φ → ∀ y ψ )", h1, h2, s1, ref="cbvaliw", note="cbvaliw")
    s3 = lb.ref("s3", "( x = y → ( ψ → φ ) )", h5, ref="biimprd", note="biimprd")
    s4 = lb.ref("s4", "( y = x → ( ψ → φ ) )", s3, ref="equcoms", note="equcoms")
    s5 = lb.ref("s5", "( ∀ y ψ → ∀ x φ )", h3, h4, s4, ref="cbvaliw", note="cbvaliw")
    res = lb.ref("res", "( ∀ x φ ↔ ∀ y ψ )", s2, s5, ref="impbii", note="impbii")
    return lb.build(res)

def prove_cbvalvw(sys: System) -> Proof:
    """Change bound variable.  Uses only Tarski's FOL axiom schemes.  See
    ~ cbvalv for a version with fewer disjoint variable conditions but
    requiring more axioms.  (Contributed by NM, 9-Apr-2017.)  (Proof
    shortened by Wolf Lammen, 28-Feb-2018.)
    """
    lb = ProofBuilder(sys, "cbvalvw")
    h1 = lb.hyp("cbvalvw.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ x φ → ∀ y ∀ x φ )", ref="ax-5", note="ax-5")
    s2 = lb.ref("s2", "( ¬ ψ → ∀ x ¬ ψ )", ref="ax-5", note="ax-5")
    s3 = lb.ref("s3", "( ∀ y ψ → ∀ x ∀ y ψ )", ref="ax-5", note="ax-5")
    s4 = lb.ref("s4", "( ¬ φ → ∀ y ¬ φ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ∀ x φ ↔ ∀ y ψ )", s1, s2, s3, s4, h1, ref="cbvalw", note="cbvalw")
    return lb.build(res)

def prove_cbvexvw(sys: System) -> Proof:
    """Change bound variable.  Uses only Tarski's FOL axiom schemes.  See
    ~ cbvexv for a version with fewer disjoint variable conditions but
    requiring more axioms.  (Contributed by NM, 19-Apr-2017.)
    """
    lb = ProofBuilder(sys, "cbvexvw")
    h1 = lb.hyp("cbvalvw.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = y → ( ¬ φ ↔ ¬ ψ ) )", h1, ref="notbid", note="notbid")
    s2 = lb.ref("s2", "( ∀ x ¬ φ ↔ ∀ y ¬ ψ )", s1, ref="cbvalvw", note="cbvalvw")
    s3 = lb.ref("s3", "( ¬ ∀ x ¬ φ ↔ ¬ ∀ y ¬ ψ )", s2, ref="notbii", note="notbii")
    s4 = lb.ref("s4", "( ∃ x φ ↔ ¬ ∀ x ¬ φ )", ref="df-ex", note="df-ex")
    s5 = lb.ref("s5", "( ∃ y ψ ↔ ¬ ∀ y ¬ ψ )", ref="df-ex", note="df-ex")
    res = lb.ref("res", "( ∃ x φ ↔ ∃ y ψ )", s3, s4, s5, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

def prove_cbvaldvaw(sys: System) -> Proof:
    """Rule used to change the bound variable in a universal quantifier with
    implicit substitution.  Deduction form.  Version of ~ cbvaldva with a
    disjoint variable condition, requiring fewer axioms.  (Contributed by
    David Moews, 1-May-2017.)  Avoid ~ ax-13 .  (Revised by GG,
    10-Jan-2024.)  Reduce axiom usage, along an idea of GG. (Revised by Wolf
    Lammen, 10-Feb-2024.)
    """
    lb = ProofBuilder(sys, "cbvaldvaw")
    h1 = lb.hyp("cbvaldvaw.1", "( ( φ ∧ x = y ) → ( ψ ↔ χ ) )")
    s1 = lb.ref("s1", "( ( x = y ∧ φ ) → ( ψ ↔ χ ) )", h1, ref="ancoms", note="ancoms")
    s2 = lb.ref("s2", "( x = y → ( ( φ → ψ ) ↔ ( φ → χ ) ) )", s1, ref="pm5.74da", note="pm5.74da")
    s3 = lb.ref("s3", "( ∀ x ( φ → ψ ) ↔ ∀ y ( φ → χ ) )", s2, ref="cbvalvw", note="cbvalvw")
    s4 = lb.ref("s4", "( ∀ x ( φ → ψ ) ↔ ( φ → ∀ x ψ ) )", ref="19.21v", note="19.21v")
    s5 = lb.ref("s5", "( ∀ y ( φ → χ ) ↔ ( φ → ∀ y χ ) )", ref="19.21v", note="19.21v")
    s6 = lb.ref("s6", "( ( φ → ∀ x ψ ) ↔ ( φ → ∀ y χ ) )", s3, s4, s5, ref="3bitr3i", note="3bitr3i")
    res = lb.ref("res", "( φ → ( ∀ x ψ ↔ ∀ y χ ) )", s6, ref="pm5.74ri", note="pm5.74ri")
    return lb.build(res)

def prove_cbvexdvaw(sys: System) -> Proof:
    """Rule used to change the bound variable in an existential quantifier with
    implicit substitution.  Deduction form.  Version of ~ cbvexdva with a
    disjoint variable condition, requiring fewer axioms.  (Contributed by
    David Moews, 1-May-2017.)  Avoid ~ ax-13 .  (Revised by GG,
    10-Jan-2024.)  Reduce axiom usage.  (Revised by Wolf Lammen,
    10-Feb-2024.)
    """
    lb = ProofBuilder(sys, "cbvexdvaw")
    h1 = lb.hyp("cbvaldvaw.1", "( ( φ ∧ x = y ) → ( ψ ↔ χ ) )")
    s1 = lb.ref("s1", "( ( φ ∧ x = y ) → ( ¬ ψ ↔ ¬ χ ) )", h1, ref="notbid", note="notbid")
    s2 = lb.ref("s2", "( φ → ( ∀ x ¬ ψ ↔ ∀ y ¬ χ ) )", s1, ref="cbvaldvaw", note="cbvaldvaw")
    s3 = lb.ref("s3", "( ∀ x ¬ ψ ↔ ¬ ∃ x ψ )", ref="alnex", note="alnex")
    s4 = lb.ref("s4", "( ∀ y ¬ χ ↔ ¬ ∃ y χ )", ref="alnex", note="alnex")
    s5 = lb.ref("s5", "( φ → ( ¬ ∃ x ψ ↔ ¬ ∃ y χ ) )", s2, s3, s4, ref="3bitr3g", note="3bitr3g")
    res = lb.ref("res", "( φ → ( ∃ x ψ ↔ ∃ y χ ) )", s5, ref="con4bid", note="con4bid")
    return lb.build(res)

def prove_cbval2vw(sys: System) -> Proof:
    """Rule used to change bound variables, using implicit substitution.
    Version of ~ cbval2vv with more disjoint variable conditions, which
    requires fewer axioms .  (Contributed by NM, 4-Feb-2005.)  Avoid
    ~ ax-13 .  (Revised by GG, 10-Jan-2024.)
    """
    lb = ProofBuilder(sys, "cbval2vw")
    h1 = lb.hyp("cbval2vw.1", "( ( x = z ∧ y = w ) → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = z → ( ∀ y φ ↔ ∀ w ψ ) )", h1, ref="cbvaldvaw", note="cbvaldvaw")
    res = lb.ref("res", "( ∀ x ∀ y φ ↔ ∀ z ∀ w ψ )", s1, ref="cbvalvw", note="cbvalvw")
    return lb.build(res)

def prove_cbvex2vw(sys: System) -> Proof:
    """Rule used to change bound variables, using implicit substitution.
    Version of ~ cbvex2vv with more disjoint variable conditions, which
    requires fewer axioms .  (Contributed by NM, 26-Jul-1995.)  Avoid
    ~ ax-13 .  (Revised by GG, 10-Jan-2024.)
    """
    lb = ProofBuilder(sys, "cbvex2vw")
    h1 = lb.hyp("cbval2vw.1", "( ( x = z ∧ y = w ) → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = z → ( ∃ y φ ↔ ∃ w ψ ) )", h1, ref="cbvexdvaw", note="cbvexdvaw")
    res = lb.ref("res", "( ∃ x ∃ y φ ↔ ∃ z ∃ w ψ )", s1, ref="cbvexvw", note="cbvexvw")
    return lb.build(res)

def prove_cbvex4vw(sys: System) -> Proof:
    """Rule used to change bound variables, using implicit substitution.
    Version of ~ cbvex4v with more disjoint variable conditions, which
    requires fewer axioms.  (Contributed by NM, 26-Jul-1995.)  Avoid
    ~ ax-13 .  (Revised by GG, 10-Jan-2024.)
    """
    lb = ProofBuilder(sys, "cbvex4vw")
    h1 = lb.hyp("cbvex4vw.1", "( ( x = v ∧ y = u ) → ( φ ↔ ψ ) )")
    h2 = lb.hyp("cbvex4vw.2", "( ( z = f ∧ w = g ) → ( ψ ↔ χ ) )")
    s1 = lb.ref("s1", "( ( x = v ∧ y = u ) → ( ∃ z ∃ w φ ↔ ∃ z ∃ w ψ ) )", h1, ref="2exbidv", note="2exbidv")
    s2 = lb.ref("s2", "( ∃ x ∃ y ∃ z ∃ w φ ↔ ∃ v ∃ u ∃ z ∃ w ψ )", s1, ref="cbvex2vw", note="cbvex2vw")
    s3 = lb.ref("s3", "( ∃ z ∃ w ψ ↔ ∃ f ∃ g χ )", h2, ref="cbvex2vw", note="cbvex2vw")
    s4 = lb.ref("s4", "( ∃ v ∃ u ∃ z ∃ w ψ ↔ ∃ v ∃ u ∃ f ∃ g χ )", s3, ref="2exbii", note="2exbii")
    res = lb.ref("res", "( ∃ x ∃ y ∃ z ∃ w φ ↔ ∃ v ∃ u ∃ f ∃ g χ )", s2, s4, ref="bitri", note="bitri")
    return lb.build(res)

def prove_alcomimw(sys: System) -> Proof:
    """Weak version of ~ ax-11 .  See ~ alcomw for the biconditional form.
    Uses only Tarski's FOL axiom schemes.  (Contributed by NM, 10-Apr-2017.)
    (Proof shortened by Wolf Lammen, 28-Dec-2023.)
    """
    lb = ProofBuilder(sys, "alcomimw")
    h1 = lb.hyp("alcomimw.1", "( y = z → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ y φ ↔ ∀ z ψ )", h1, ref="cbvalvw", note="cbvalvw")
    s2 = lb.ref("s2", "( ∀ y φ → ∀ z ψ )", s1, ref="biimpi", note="biimpi")
    s3 = lb.ref("s3", "( ∀ x ∀ y φ → ∀ x ∀ z ψ )", s2, ref="alimi", note="alimi")
    s4 = lb.ref("s4", "( ∀ x ∀ z ψ → ∀ y ∀ x ∀ z ψ )", ref="ax-5", note="ax-5")
    s5 = lb.ref("s5", "( y = z → ( ψ → φ ) )", h1, ref="biimprd", note="biimprd")
    s6 = lb.ref("s6", "( z = y → ( ψ → φ ) )", s5, ref="equcoms", note="equcoms")
    s7 = lb.ref("s7", "( ∀ z ψ → φ )", s6, ref="spimvw", note="spimvw")
    s8 = lb.ref("s8", "( ∀ y ∀ x ∀ z ψ → ∀ y ∀ x φ )", s7, ref="2alimi", note="2alimi")
    res = lb.ref("res", "( ∀ x ∀ y φ → ∀ y ∀ x φ )", s3, s4, s8, ref="3syl", note="3syl")
    return lb.build(res)

def prove_excomimw(sys: System) -> Proof:
    """Weak version of ~ excomim .  Uses only Tarski's FOL axiom schemes.
    (Contributed by BTernaryTau, 23-Jun-2025.)
    """
    lb = ProofBuilder(sys, "excomimw")
    h1 = lb.hyp("excomimw.1", "( x = z → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = z → ( ¬ φ ↔ ¬ ψ ) )", h1, ref="notbid", note="notbid")
    s2 = lb.ref("s2", "( ∀ y ∀ x ¬ φ → ∀ x ∀ y ¬ φ )", s1, ref="alcomimw", note="alcomimw")
    s3 = lb.ref("s3", "( ¬ ∀ x ∀ y ¬ φ → ¬ ∀ y ∀ x ¬ φ )", s2, ref="con3i", note="con3i")
    s4 = lb.ref("s4", "( ∃ x ∃ y φ ↔ ¬ ∀ x ∀ y ¬ φ )", ref="2exnaln", note="2exnaln")
    s5 = lb.ref("s5", "( ∃ y ∃ x φ ↔ ¬ ∀ y ∀ x ¬ φ )", ref="2exnaln", note="2exnaln")
    res = lb.ref("res", "( ∃ x ∃ y φ → ∃ y ∃ x φ )", s3, s4, s5, ref="3imtr4i", note="3imtr4i")
    return lb.build(res)

def prove_alcomw(sys: System) -> Proof:
    """Weak version of ~ alcom and biconditional form of ~ alcomimw .  Uses
    only Tarski's FOL axiom schemes.  (Contributed by BTernaryTau,
    28-Dec-2024.)
    """
    lb = ProofBuilder(sys, "alcomw")
    h1 = lb.hyp("alcomw.1", "( x = w → ( φ ↔ ψ ) )")
    h2 = lb.hyp("alcomw.2", "( y = z → ( φ ↔ χ ) )")
    s1 = lb.ref("s1", "( ∀ x ∀ y φ → ∀ y ∀ x φ )", h2, ref="alcomimw", note="alcomimw")
    s2 = lb.ref("s2", "( ∀ y ∀ x φ → ∀ x ∀ y φ )", h1, ref="alcomimw", note="alcomimw")
    res = lb.ref("res", "( ∀ x ∀ y φ ↔ ∀ y ∀ x φ )", s1, s2, ref="impbii", note="impbii")
    return lb.build(res)

def prove_excomw(sys: System) -> Proof:
    """Weak version of ~ excom and biconditional form of ~ excomimw .  Uses
    only Tarski's FOL axiom schemes.  (Contributed by TM, 24-Jan-2026.)
    """
    lb = ProofBuilder(sys, "excomw")
    h1 = lb.hyp("excomw.1", "( x = w → ( φ ↔ ψ ) )")
    h2 = lb.hyp("excomw.2", "( y = z → ( φ ↔ χ ) )")
    s1 = lb.ref("s1", "( ∃ x ∃ y φ → ∃ y ∃ x φ )", h1, ref="excomimw", note="excomimw")
    s2 = lb.ref("s2", "( ∃ y ∃ x φ → ∃ x ∃ y φ )", h2, ref="excomimw", note="excomimw")
    res = lb.ref("res", "( ∃ x ∃ y φ ↔ ∃ y ∃ x φ )", s1, s2, ref="impbii", note="impbii")
    return lb.build(res)

def prove_hbn1fw(sys: System) -> Proof:
    """Weak version of ~ ax-10 from which we can prove any ~ ax-10 instance not
    involving wff variables or bundling.  Uses only Tarski's FOL axiom
    schemes.  (Contributed by NM, 19-Apr-2017.)  (Proof shortened by Wolf
    Lammen, 28-Feb-2018.)
    """
    lb = ProofBuilder(sys, "hbn1fw")
    h1 = lb.hyp("hbn1fw.1", "( ∀ x φ → ∀ y ∀ x φ )")
    h2 = lb.hyp("hbn1fw.2", "( ¬ ψ → ∀ x ¬ ψ )")
    h3 = lb.hyp("hbn1fw.3", "( ∀ y ψ → ∀ x ∀ y ψ )")
    h4 = lb.hyp("hbn1fw.4", "( ¬ φ → ∀ y ¬ φ )")
    h5 = lb.hyp("hbn1fw.5", "( ¬ ∀ y ψ → ∀ x ¬ ∀ y ψ )")
    h6 = lb.hyp("hbn1fw.6", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ x φ ↔ ∀ y ψ )", h1, h2, h3, h4, h6, ref="cbvalw", note="cbvalw")
    s2 = lb.ref("s2", "( ¬ ∀ x φ ↔ ¬ ∀ y ψ )", s1, ref="notbii", note="notbii")
    res = lb.ref("res", "( ¬ ∀ x φ → ∀ x ¬ ∀ x φ )", s2, h5, ref="hbxfrbi", note="hbxfrbi")
    return lb.build(res)

def prove_hbn1w(sys: System) -> Proof:
    """Weak version of ~ hbn1 .  Uses only Tarski's FOL axiom schemes.
    (Contributed by NM, 9-Apr-2017.)
    """
    lb = ProofBuilder(sys, "hbn1w")
    h1 = lb.hyp("hbn1w.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ x φ → ∀ y ∀ x φ )", ref="ax-5", note="ax-5")
    s2 = lb.ref("s2", "( ¬ ψ → ∀ x ¬ ψ )", ref="ax-5", note="ax-5")
    s3 = lb.ref("s3", "( ∀ y ψ → ∀ x ∀ y ψ )", ref="ax-5", note="ax-5")
    s4 = lb.ref("s4", "( ¬ φ → ∀ y ¬ φ )", ref="ax-5", note="ax-5")
    s5 = lb.ref("s5", "( ¬ ∀ y ψ → ∀ x ¬ ∀ y ψ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ¬ ∀ x φ → ∀ x ¬ ∀ x φ )", s1, s2, s3, s4, s5, h1, ref="hbn1fw", note="hbn1fw")
    return lb.build(res)

def prove_hba1w(sys: System) -> Proof:
    """Weak version of ~ hba1 .  See comments for ~ ax10w .  Uses only Tarski's
    FOL axiom schemes.  (Contributed by NM, 9-Apr-2017.)  (Proof shortened
    by Wolf Lammen, 10-Oct-2021.)
    """
    lb = ProofBuilder(sys, "hba1w")
    h1 = lb.hyp("hbn1w.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ x φ ↔ ∀ y ψ )", h1, ref="cbvalvw", note="cbvalvw")
    s2 = lb.ref("s2", "( ¬ ∀ x φ ↔ ¬ ∀ y ψ )", s1, ref="notbii", note="notbii")
    s3 = lb.ref("s3", "( x = y → ( ¬ ∀ x φ ↔ ¬ ∀ y ψ ) )", s2, ref="a1i", note="a1i")
    s4 = lb.ref("s4", "( ∀ x ¬ ∀ x φ → ¬ ∀ x φ )", s3, ref="spw", note="spw")
    s5 = lb.ref("s5", "( ∀ x φ → ¬ ∀ x ¬ ∀ x φ )", s4, ref="con2i", note="con2i")
    s6 = lb.ref("s6", "( ∀ x φ ↔ ∀ y ψ )", h1, ref="cbvalvw", note="cbvalvw")
    s7 = lb.ref("s7", "( ¬ ∀ x φ ↔ ¬ ∀ y ψ )", s6, ref="notbii", note="notbii")
    s8 = lb.ref("s8", "( x = y → ( ¬ ∀ x φ ↔ ¬ ∀ y ψ ) )", s7, ref="a1i", note="a1i")
    s9 = lb.ref("s9", "( ¬ ∀ x ¬ ∀ x φ → ∀ x ¬ ∀ x ¬ ∀ x φ )", s8, ref="hbn1w", note="hbn1w")
    s10 = lb.ref("s10", "( ¬ ∀ x φ → ∀ x ¬ ∀ x φ )", h1, ref="hbn1w", note="hbn1w")
    s11 = lb.ref("s11", "( ¬ ∀ x ¬ ∀ x φ → ∀ x φ )", s10, ref="con1i", note="con1i")
    s12 = lb.ref("s12", "( ∀ x ¬ ∀ x ¬ ∀ x φ → ∀ x ∀ x φ )", s11, ref="alimi", note="alimi")
    res = lb.ref("res", "( ∀ x φ → ∀ x ∀ x φ )", s5, s9, s12, ref="3syl", note="3syl")
    return lb.build(res)

def prove_hbe1w(sys: System) -> Proof:
    """Weak version of ~ hbe1 .  See comments for ~ ax10w .  Uses only Tarski's
    FOL axiom schemes.  (Contributed by NM, 19-Apr-2017.)
    """
    lb = ProofBuilder(sys, "hbe1w")
    h1 = lb.hyp("hbn1w.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∃ x φ ↔ ¬ ∀ x ¬ φ )", ref="df-ex", note="df-ex")
    s2 = lb.ref("s2", "( x = y → ( ¬ φ ↔ ¬ ψ ) )", h1, ref="notbid", note="notbid")
    s3 = lb.ref("s3", "( ¬ ∀ x ¬ φ → ∀ x ¬ ∀ x ¬ φ )", s2, ref="hbn1w", note="hbn1w")
    res = lb.ref("res", "( ∃ x φ → ∀ x ∃ x φ )", s1, s3, ref="hbxfrbi", note="hbxfrbi")
    return lb.build(res)

def prove_hbalw(sys: System) -> Proof:
    """Weak version of ~ hbal .  Uses only Tarski's FOL axiom schemes.  Unlike
    ~ hbal , this theorem requires that ` x ` and ` y ` be distinct, i.e.,
    not be bundled.  (Contributed by NM, 19-Apr-2017.)
    """
    lb = ProofBuilder(sys, "hbalw")
    h1 = lb.hyp("hbalw.1", "( x = z → ( φ ↔ ψ ) )")
    h2 = lb.hyp("hbalw.2", "( φ → ∀ x φ )")
    s1 = lb.ref("s1", "( ∀ y φ → ∀ y ∀ x φ )", h2, ref="alimi", note="alimi")
    s2 = lb.ref("s2", "( ∀ y ∀ x φ → ∀ x ∀ y φ )", h1, ref="alcomimw", note="alcomimw")
    res = lb.ref("res", "( ∀ y φ → ∀ x ∀ y φ )", s1, s2, ref="syl", note="syl")
    return lb.build(res)

def prove_19_8aw(sys: System) -> Proof:
    """If a formula is true, then it is true for at least one instance.  This
    is to ~ 19.8a what ~ spw is to ~ sp .  (Contributed by SN,
    26-Sep-2024.)
    """
    lb = ProofBuilder(sys, "19.8aw")
    h1 = lb.hyp("19.8aw.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ x ¬ φ ↔ ¬ ∃ x φ )", ref="alnex", note="alnex")
    s2 = lb.ref("s2", "( x = y → ( ¬ φ ↔ ¬ ψ ) )", h1, ref="notbid", note="notbid")
    s3 = lb.ref("s3", "( ∀ x ¬ φ → ¬ φ )", s2, ref="spw", note="spw")
    s4 = lb.ref("s4", "( ¬ ∃ x φ → ¬ φ )", s1, s3, ref="sylbir", note="sylbir")
    res = lb.ref("res", "( φ → ∃ x φ )", s4, ref="con4i", note="con4i")
    return lb.build(res)

def prove_exexw(sys: System) -> Proof:
    """Existential quantification over a given variable is idempotent.  Weak
    version of ~ bj-exexbiex , requiring fewer axioms.  (Contributed by GG,
    4-Nov-2024.)
    """
    lb = ProofBuilder(sys, "exexw")
    h1 = lb.hyp("exexw.1", "( x = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( x = y → ( ¬ φ ↔ ¬ ψ ) )", h1, ref="notbid", note="notbid")
    s2 = lb.ref("s2", "( ∀ x ¬ φ → ∀ x ∀ x ¬ φ )", s1, ref="hba1w", note="hba1w")
    s3 = lb.ref("s3", "( x = y → ( ¬ φ ↔ ¬ ψ ) )", h1, ref="notbid", note="notbid")
    s4 = lb.ref("s4", "( ∀ x ¬ φ → ¬ φ )", s3, ref="spw", note="spw")
    s5 = lb.ref("s5", "( ∀ x ∀ x ¬ φ → ∀ x ¬ φ )", s4, ref="alimi", note="alimi")
    s6 = lb.ref("s6", "( ∀ x ¬ φ ↔ ∀ x ∀ x ¬ φ )", s2, s5, ref="impbii", note="impbii")
    s7 = lb.ref("s7", "( ¬ ∀ x ¬ φ ↔ ¬ ∀ x ∀ x ¬ φ )", s6, ref="notbii", note="notbii")
    s8 = lb.ref("s8", "( ∃ x φ ↔ ¬ ∀ x ¬ φ )", ref="df-ex", note="df-ex")
    s9 = lb.ref("s9", "( ∃ x ∃ x φ ↔ ¬ ∀ x ∀ x ¬ φ )", ref="2exnaln", note="2exnaln")
    res = lb.ref("res", "( ∃ x φ ↔ ∃ x ∃ x φ )", s7, s8, s9, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

def prove_spaev(sys: System) -> Proof:
    """A special instance of ~ sp applied to an equality with a disjoint
    variable condition.  Unlike the more general ~ sp , we can prove this
    without ~ ax-12 .  Instance of ~ aeveq .

    The antecedent ` A. x x = y ` with distinct ` x ` and ` y ` is a
    characteristic of a degenerate universe, in which just one object
    exists.  Actually more than one object may still exist, but if so, we
    give up on equality as a discriminating term.

    Separating this degenerate case from a richer universe, where inequality
    is possible, is a common proof idea.  The name of this theorem follows a
    convention, where the condition ` A. x x = y ` is denoted by 'aev', a
    shorthand for 'all equal, with a distinct variable condition'.
    (Contributed by Wolf Lammen, 14-Mar-2021.)
    """
    lb = ProofBuilder(sys, "spaev")
    s1 = lb.ref("s1", "( x = z → ( x = y ↔ z = y ) )", ref="equequ1", note="equequ1")
    res = lb.ref("res", "( ∀ x x = y → x = y )", s1, ref="spw", note="spw")
    return lb.build(res)

def prove_cbvaev(sys: System) -> Proof:
    """Change bound variable in an equality with a disjoint variable condition.
    Instance of ~ aev .  (Contributed by NM, 22-Jul-2015.)  (Revised by BJ,
    18-Jun-2019.)
    """
    lb = ProofBuilder(sys, "cbvaev")
    s1 = lb.ref("s1", "( x = t → ( x = y → t = y ) )", ref="ax7", note="ax7")
    s2 = lb.ref("s2", "( ∀ x x = y → ∀ t t = y )", s1, ref="cbvalivw", note="cbvalivw")
    s3 = lb.ref("s3", "( t = z → ( t = y → z = y ) )", ref="ax7", note="ax7")
    s4 = lb.ref("s4", "( ∀ t t = y → ∀ z z = y )", s3, ref="cbvalivw", note="cbvalivw")
    res = lb.ref("res", "( ∀ x x = y → ∀ z z = y )", s2, s4, ref="syl", note="syl")
    return lb.build(res)

def prove_aevlem0(sys: System) -> Proof:
    """Lemma for ~ aevlem .  Instance of ~ aev .  (Contributed by NM,
    8-Jul-2016.)  (Proof shortened by Wolf Lammen, 17-Feb-2018.)  Remove
    dependency on ~ ax-12 .  (Revised by Wolf Lammen, 14-Mar-2021.)  Extract
    from proof of a former lemma for ~ axc11n and add DV condition to reduce
    axiom usage.  (Revised by BJ, 29-Mar-2021.)  (Proof shortened by Wolf
    Lammen, 30-Mar-2021.)
    """
    lb = ProofBuilder(sys, "aevlem0")
    s1 = lb.ref("s1", "( ∀ x x = y → x = y )", ref="spaev", note="spaev")
    s2 = lb.ref("s2", "( ∀ x x = y → ∀ z x = y )", s1, ref="alrimiv", note="alrimiv")
    s3 = lb.ref("s3", "( ∀ x x = y → ∀ z z = y )", ref="cbvaev", note="cbvaev")
    s4 = lb.ref("s4", "( x = y → ( z = y → z = x ) )", ref="equeuclr", note="equeuclr")
    s5 = lb.ref("s5", "( ∀ z x = y → ( ∀ z z = y → ∀ z z = x ) )", s4, ref="al2imi", note="al2imi")
    res = lb.ref("res", "( ∀ x x = y → ∀ z z = x )", s2, s3, s5, ref="sylc", note="sylc")
    return lb.build(res)

def prove_aevlem(sys: System) -> Proof:
    """Lemma for ~ aev and ~ axc16g .  Change free and bound variables.
    Instance of ~ aev .  (Contributed by NM, 22-Jul-2015.)  (Proof shortened
    by Wolf Lammen, 17-Feb-2018.)  Remove dependency on ~ ax-13 , along an
    idea of BJ. (Revised by Wolf Lammen, 30-Nov-2019.)  Reduce axiom usage.
    (Revised by BJ, 29-Mar-2021.)
    """
    lb = ProofBuilder(sys, "aevlem")
    s1 = lb.ref("s1", "( ∀ x x = y → ∀ u u = y )", ref="cbvaev", note="cbvaev")
    s2 = lb.ref("s2", "( ∀ u u = y → ∀ x x = u )", ref="aevlem0", note="aevlem0")
    s3 = lb.ref("s3", "( ∀ x x = u → ∀ t t = u )", ref="cbvaev", note="cbvaev")
    s4 = lb.ref("s4", "( ∀ t t = u → ∀ z z = t )", ref="aevlem0", note="aevlem0")
    res = lb.ref("res", "( ∀ x x = y → ∀ z z = t )", s1, s2, s3, s4, ref="4syl", note="4syl")
    return lb.build(res)

def prove_aeveq(sys: System) -> Proof:
    """The antecedent ` A. x x = y ` with a disjoint variable condition
    (typical of a one-object universe) forces equality of everything.
    (Contributed by Wolf Lammen, 19-Mar-2021.)
    """
    lb = ProofBuilder(sys, "aeveq")
    s1 = lb.ref("s1", "( ∀ x x = y → ∀ u u = z )", ref="aevlem", note="aevlem")
    s2 = lb.ref("s2", "∃ u u = t", ref="ax6ev", note="ax6ev")
    s3 = lb.ref("s3", "( u = z → ( u = t → z = t ) )", ref="ax7", note="ax7")
    s4 = lb.ref("s4", "( ∀ u u = z → ( ∃ u u = t → ∃ u z = t ) )", s3, ref="aleximi", note="aleximi")
    s5 = lb.ref("s5", "( ∀ u u = z → ∃ u z = t )", s2, s4, ref="mpi", note="mpi")
    s6 = lb.ref("s6", "( ∃ u z = t → z = t )", ref="ax5e", note="ax5e")
    res = lb.ref("res", "( ∀ x x = y → z = t )", s1, s5, s6, ref="3syl", note="3syl")
    return lb.build(res)

def prove_aev(sys: System) -> Proof:
    """A "distinctor elimination" lemma with no disjoint variable conditions on
    variables in the consequent.  (Contributed by NM, 8-Nov-2006.)  Remove
    dependency on ~ ax-11 .  (Revised by Wolf Lammen, 7-Sep-2018.)  Remove
    dependency on ~ ax-13 , inspired by an idea of BJ. (Revised by Wolf
    Lammen, 30-Nov-2019.)  Remove dependency on ~ ax-12 .  (Revised by Wolf
    Lammen, 19-Mar-2021.)
    """
    lb = ProofBuilder(sys, "aev")
    s1 = lb.ref("s1", "( ∀ x x = y → ∀ v v = w )", ref="aevlem", note="aevlem")
    s2 = lb.ref("s2", "( ∀ v v = w → t = u )", ref="aeveq", note="aeveq")
    s3 = lb.ref("s3", "( ∀ v v = w → ∀ z t = u )", s2, ref="alrimiv", note="alrimiv")
    res = lb.ref("res", "( ∀ x x = y → ∀ z t = u )", s1, s3, ref="syl", note="syl")
    return lb.build(res)

def prove_aev2(sys: System) -> Proof:
    """A version of ~ aev with two universal quantifiers in the consequent.
    One can prove similar statements with arbitrary numbers of universal
    quantifiers in the consequent (the series begins with ~ aeveq , ~ aev ,
    ~ aev2 ).

    Using ~ aev and ~ alrimiv , one can actually prove (with no more axioms)
    any scheme of the form ` ( A. x x = y -> ` PHI) , DV ` ( x , y ) ` where
    PHI involves only setvar variables and the connectors ` -> ` , ` <-> ` ,
    ` /\\ ` , ` \\/ ` , ` T. ` , ` = ` , ` A. ` , ` E. ` , ` E* ` , ` E! ` ,
    ` F/ ` .  An example is given by ~ aevdemo .  This list cannot be
    extended to ` -. ` or ` F. ` since the scheme ` A. x x = y ` is
    consistent with ~ ax-mp , ~ ax-gen , ~ ax-1 -- ~ ax-13 (as the
    one-element universe shows), so for instance ` ( A. x x = y -> F. ) , `
    DV ` ( x , y ) ` is not provable from these axioms alone (indeed, ~ dtru
    uses non-logical axioms as well).  (Contributed by BJ, 23-Mar-2021.)
    """
    lb = ProofBuilder(sys, "aev2")
    s1 = lb.ref("s1", "( ∀ x x = y → ∀ w w = s )", ref="aev", note="aev")
    s2 = lb.ref("s2", "( ∀ w w = s → ∀ t u = v )", ref="aev", note="aev")
    s3 = lb.ref("s3", "( ∀ w w = s → ∀ z ∀ t u = v )", s2, ref="alrimiv", note="alrimiv")
    res = lb.ref("res", "( ∀ x x = y → ∀ z ∀ t u = v )", s1, s3, ref="syl", note="syl")
    return lb.build(res)

def prove_hbaev(sys: System) -> Proof:
    """All variables are effectively bound in an identical variable specifier.
    Version of ~ hbae with a disjoint variable condition, requiring fewer
    axioms.  Instance of ~ aev2 .  (Contributed by NM, 13-May-1993.)  Reduce
    axiom usage.  (Revised by Wolf Lammen, 22-Mar-2021.)
    """
    lb = ProofBuilder(sys, "hbaev")
    res = lb.ref("res", "( ∀ x x = y → ∀ z ∀ x x = y )", ref="aev2", note="aev2")
    return lb.build(res)

def prove_naev(sys: System) -> Proof:
    """If some set variables can assume different values, then any two distinct
    set variables cannot always be the same.  (Contributed by Wolf Lammen,
    10-Aug-2019.)
    """
    lb = ProofBuilder(sys, "naev")
    s1 = lb.ref("s1", "( ∀ u u = v → ∀ x x = y )", ref="aev", note="aev")
    res = lb.ref("res", "( ¬ ∀ x x = y → ¬ ∀ u u = v )", s1, ref="con3i", note="con3i")
    return lb.build(res)

def prove_naev2(sys: System) -> Proof:
    """Generalization of ~ hbnaev .  (Contributed by Wolf Lammen,
    9-Apr-2021.)
    """
    lb = ProofBuilder(sys, "naev2")
    s1 = lb.ref("s1", "( ¬ ∀ x x = y → ¬ ∀ v v = w )", ref="naev", note="naev")
    s2 = lb.ref("s2", "( ¬ ∀ v v = w → ∀ z ¬ ∀ v v = w )", ref="ax-5", note="ax-5")
    s3 = lb.ref("s3", "( ¬ ∀ v v = w → ¬ ∀ t t = u )", ref="naev", note="naev")
    s4 = lb.ref("s4", "( ∀ z ¬ ∀ v v = w → ∀ z ¬ ∀ t t = u )", s3, ref="alimi", note="alimi")
    res = lb.ref("res", "( ¬ ∀ x x = y → ∀ z ¬ ∀ t t = u )", s1, s2, s4, ref="3syl", note="3syl")
    return lb.build(res)

def prove_hbnaev(sys: System) -> Proof:
    """Any variable is free in ` -. A. x x = y ` , if ` x ` and ` y ` are
    distinct.  This condition is dropped in ~ hbnae , at the expense of more
    axiom dependencies.  Instance of ~ naev2 .  (Contributed by NM,
    13-May-1993.)  (Revised by Wolf Lammen, 9-Apr-2021.)
    """
    lb = ProofBuilder(sys, "hbnaev")
    res = lb.ref("res", "( ¬ ∀ x x = y → ∀ z ¬ ∀ x x = y )", ref="naev2", note="naev2")
    return lb.build(res)

def prove_justify_df(sys: System) -> Proof:
    """Metamath handles substitution uniformly.  Any expression may replace a
    variable provided that their types are compatible and that no
    substituting expression contains a set variable prohibited by a distinct
    variable condition.

    The axioms are formulated so that every such substitution is valid when
    the side conditions are satisfied.  Consequently, every theorem derived
    from the axioms inherits the same substitution property.  This agrees
    with standard mathematical practice, where substitution is unrestricted
    apart from type and freshness requirements.

    Definitions introduce abbreviations for expressions represented by their
    definiens, usually the right-hand side of a defining biconditional.
    When a definition contains dummy variables, however, the definiens is
    not uniquely determined by the definiendum, since the names of fresh
    bound variables do not appear in the definiendum.  Definitions of this
    kind are meaningful only if the particular names chosen for dummy
    variables are irrelevant.

    In ordinary logic and mathematics, renaming fresh bound variables
    (alpha-renaming) is regarded as insignificant.  Metamath's substitution
    mechanism reflects this principle, and therefore definitions must also
    respect it.  Early versions of this database relied on this convention
    implicitly.  Beginning in 2023, definitions involving dummy variables
    were accompanied by justification theorems (for example, ~ rename-sb )
    showing that alpha-renaming the definiens yields an equivalent
    expression.  Consequently, different choices of dummy variable names
    cannot produce equivalences that are not already derivable within the
    formal system.

    Metamath records not only proofs but also the list of axioms on which
    they depend.  Since definitions are intended merely as abbreviations,
    their use should not affect these dependency lists.  Unfortunately, the
    simple form of definition used before 2026 did not preserve this
    invariance.  Two instances of a definition differing only in the names
    of dummy variables could be used to reprove the corresponding
    justification theorem with unusually low axiom usage, unattainable by
    proofs using axioms alone.  Thus the recorded dependencies could depend
    on whether the definition was used or expanded away.

    Beginning in February 2026, definitions involving dummy variables were
    therefore modified to incorporate alpha-renaming explicitly.  In the
    intermediate scheme, the corresponding justification theorem was added
    as a hypothesis of the definition, ensuring that every use of the
    definition inherited the axioms needed to establish the renaming
    property.  This eliminated artificial reductions in dependency lists.

    Using the alpha-renaming property as an external hypothesis is, however,
    not ideal.  A better approach is to encode the property directly in the
    definiens itself.  This preserves the invariance of axiom dependencies
    while allowing reductions that are impossible with the hypothesis-based
    form.

    Formal justifications for this improved definition scheme are given in
    ~ just1-df , ~ just2-df , and ~ just3-df .  An implementation is
    provided by definition ~ df-sb and the theorems that follow, where the
    underlying techniques may be studied in greater detail.  (Contributed by
    Wolf Lammen, 12-Jun-2026.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "justify-df")
    res = lb.ref("res", "φ", ref="justify-df.1", note="justify-df.1")
    return lb.build(res)

def prove_just1_df(sys: System) -> Proof:
    """First justification theorem for definitions whose definiens is a
    conjunction, as in ~ df-sb .  Here ` ph ` denotes the definiendum, while
    ` ps ` and ` ch ` represent the two components of the definiens.  The
    theorem shows that the definiendum implies either component separately.
    (Contributed by Wolf Lammen, 6-Jun-2026.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "just1-df")
    h1 = lb.hyp("just1-df.1", "( φ ↔ ( ψ ∧ χ ) )")
    res = lb.ref("res", "( φ → ψ )", h1, ref="simplbi", note="simplbi")
    return lb.build(res)

def prove_just2_df(sys: System) -> Proof:
    """Second justification theorem for definitions whose definiens is a
    conjunction, as in ~ df-sb .  If ` ph ` is equivalent to
    ` ( ps /\\ ch ) ` , then it implies ` ( ps <-> ch ) ` .  In the case of
    ~ df-sb , this expresses the invariance of the definition under
    alpha-renaming of the bound variable.  (Contributed by Wolf Lammen,
    6-Jun-2026.)
    """
    lb = ProofBuilder(sys, "just2-df")
    h1 = lb.hyp("just2-df.1", "( φ ↔ ( ψ ∧ χ ) )")
    s1 = lb.ref("s1", "( ( ψ ∧ χ ) ↔ ( ψ ∧ ( ψ ↔ χ ) ) )", ref="abab", note="abab")
    s2 = lb.ref("s2", "( φ ↔ ( ψ ∧ ( ψ ↔ χ ) ) )", h1, s1, ref="bitri", note="bitri")
    res = lb.ref("res", "( φ → ( ψ ↔ χ ) )", s2, ref="simprbi", note="simprbi")
    return lb.build(res)

def prove_just3_df(sys: System) -> Proof:
    """Third justification theorem for definitions whose definiens is a
    conjunction, as in ~ df-sb .  In addition to the defining equivalence,
    the second hypothesis requires the conjuncts of the definiens to be
    equivalent.

    When the conjuncts are quantified and differ only by a bound-variable
    renaming, this equivalence is usually obtained from an implicit
    substitution between the underlying expressions.  In some cases,
    however, it can be proved more directly and with fewer axioms.

    Under these assumptions, either conjunct implies the definiendum.
    Together with ~ just1-df , the definiendum is therefore equivalent to
    either conjunct.  (Contributed by Wolf Lammen, 6-Jun-2026.)
    """
    lb = ProofBuilder(sys, "just3-df")
    h1 = lb.hyp("just3-df.1", "( φ ↔ ( ψ ∧ χ ) )")
    h2 = lb.hyp("just3-df.2", "( ψ ↔ χ )")
    s1 = lb.ref("s1", "( ψ → ( ψ ∧ ( ψ ↔ χ ) ) )", h2, ref="jctr", note="jctr")
    s2 = lb.ref("s2", "( ( ψ ∧ χ ) ↔ ( ψ ∧ ( ψ ↔ χ ) ) )", ref="abab", note="abab")
    s3 = lb.ref("s3", "( φ ↔ ( ψ ∧ ( ψ ↔ χ ) ) )", h1, s2, ref="bitri", note="bitri")
    res = lb.ref("res", "( ψ → φ )", s1, s3, ref="sylibr", note="sylibr")
    return lb.build(res)

def prove_rename_sb(sys: System) -> Proof:
    """The equivalence needed for ~ df-sb in ~ just3-df .  It is proved from
    Tarski's FOL axiom schemes.  (Contributed by BJ, 22-Jan-2023.)
    """
    lb = ProofBuilder(sys, "rename-sb")
    s1 = lb.ref("s1", "( y = z → ( y = t ↔ z = t ) )", ref="equequ1", note="equequ1")
    s2 = lb.ref("s2", "( y = z → ( x = y ↔ x = z ) )", ref="equequ2", note="equequ2")
    s3 = lb.ref("s3", "( y = z → ( ( x = y → φ ) ↔ ( x = z → φ ) ) )", s2, ref="imbi1d", note="imbi1d")
    s4 = lb.ref("s4", "( y = z → ( ∀ x ( x = y → φ ) ↔ ∀ x ( x = z → φ ) ) )", s3, ref="albidv", note="albidv")
    s5 = lb.ref("s5", "( y = z → ( ( y = t → ∀ x ( x = y → φ ) ) ↔ ( z = t → ∀ x ( x = z → φ ) ) ) )", s1, s4, ref="imbi12d", note="imbi12d")
    res = lb.ref("res", "( ∀ y ( y = t → ∀ x ( x = y → φ ) ) ↔ ∀ z ( z = t → ∀ x ( x = z → φ ) ) )", s5, ref="cbvalvw", note="cbvalvw")
    return lb.build(res)


